window.KNOWLEDGE_DATA = [{"id":"k1","theme":"古典文法","title":"動詞の活用の種類（全9種類）","summary":"動詞の活用は全部で9種類あります。「四段・上一段・上二段・下一段・下二段・カ変・サ変・ナ変・ラ変」です。","hot":true,"source":"01_古典文法_用言の活用.md"},{"id":"k2","theme":"古典文法","title":"活用形（6つの活用形）","summary":"活用形は「未然形・連用形・終止形・連体形・已然形・命令形」の6つです。未然形は打消や推量に、連用形は中止や過去に、連体形は体言や係り結びに、已然形は逆接や係り結び（こそ）に接続します。","hot":true,"source":"01_古典文法_用言の活用.md"},{"id":"k3","theme":"古典文法","title":"四段活用","summary":"四段活用は、ア・イ・ウ・エの四つの段にわたって活用する動詞です。「書く（書か・書き・書く・書く・書け・書け）」が代表例で、最も語数が多い活用です。","hot":false,"source":"01_古典文法_用言の活用.md"},{"id":"k4","theme":"古典文法","title":"上一段活用","summary":"上一段活用は、イ段のみで活用する動詞で語数が少なく暗記対象です。「干る・射る・鋳る・着る・似る・煮る・見る・居る・率る」などが該当し、「ひいきにみゐる（贔屓に見入る）」の語呂で覚えます。","hot":true,"source":"01_古典文法_用言の活用.md"},{"id":"k5","theme":"古典文法","title":"下一段活用","summary":"下一段活用は、エ段のみで活用し、「蹴る」一語のみが該当します。「蹴（け）・蹴（け）・蹴る・蹴る・蹴れ・蹴よ」と活用します。","hot":true,"source":"01_古典文法_用言の活用.md"},{"id":"k6","theme":"古典文法","title":"上二段活用・下二段活用","summary":"上二段はイ・ウの二段（過ぐ・落つなど）、下二段はウ・エの二段（受く・捨つなど）で活用します。下二段は現代語の下一段にあたる動詞が多く、未然形が「エ段＋ず（受けず）」なら下二段、「イ段＋ず（過ぎず）」なら上二段と見分けます。","hot":false,"source":"01_古典文法_用言の活用.md"},{"id":"k7","theme":"古典文法","title":"変格活用（カ変・サ変・ナ変・ラ変）","summary":"変格活用は不規則な活用で語数が限られます。カ変は「来（く）」一語、サ変は「す・おはす」、ナ変は「死ぬ・往（い）ぬ」、ラ変は「あり・をり・侍り・いますがり」です。","hot":true,"source":"01_古典文法_用言の活用.md"},{"id":"k8","theme":"古典文法","title":"形容詞の活用（ク活用・シク活用）","summary":"形容詞にはク活用とシク活用の2種類があります。「なし（ク活用）」「うつくし（シク活用）」のように、連用形に「なる」を付けて「〜くなる」ならク活用、「〜しくなる」ならシク活用と見分けます。","hot":true,"source":"01_古典文法_用言の活用.md"},{"id":"k9","theme":"古典文法","title":"形容動詞の活用（ナリ活用・タリ活用）","summary":"形容動詞にはナリ活用とタリ活用があります。「静かなり（ナリ活用）」は和文に、「堂々たり（タリ活用）」は漢文訓読調の文章に多く用いられます。","hot":false,"source":"01_古典文法_用言の活用.md"},{"id":"k10","theme":"古典文法","title":"音便（イ音便・ウ音便・撥音便・促音便）","summary":"音便は発音しやすくするために語形が変化する現象です。イ音便（書きて→書いて）、ウ音便（思ひて→思うて）、撥音便（飛びて→飛んで）、促音便（取りて→取つて）の4種類があります。","hot":false,"source":"01_古典文法_用言の活用.md"},{"id":"k11","theme":"古典文法","title":"助動詞「る・らる」（受身・尊敬・自発・可能）","summary":"「る・らる」は四段・ナ変・ラ変の未然形に「る」、それ以外の未然形に「らる」が付きます。意味は受身・尊敬・自発・可能の4つです。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k12","theme":"古典文法","title":"助動詞「す・さす・しむ」（使役・尊敬）","summary":"「す・さす・しむ」は使役（〜せる）と尊敬（〜なさる）の意味を持ちます。下に尊敬語を伴うとき（例：せ給ふ）は尊敬の二重敬語になることが多く、伴わないときは使役と判断します。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k13","theme":"古典文法","title":"助動詞「ず」（打消）","summary":"「ず」は打消（〜ない）の意味で、活用語の未然形に接続します。「ず・ず・ず／ぬ・ね」の系列と「ざら・ざり・ざる・ざれ」の系列の二系統で活用する点に注意が必要です。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k14","theme":"古典文法","title":"助動詞「む・むず」（推量・意志・適当・勧誘・仮定・婉曲）","summary":"「む（ん）」は未然形接続で、推量・意志・適当・勧誘・仮定・婉曲の6つの意味があります。主語が一人称なら意志、二人称なら勧誘・適当、三人称なら推量と、主語の人称で意味を判断するのが基本です。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k15","theme":"古典文法","title":"助動詞「じ」（打消推量・打消意志）","summary":"「じ」は未然形接続で、「む」の打消にあたります。打消推量（〜ないだろう）と打消意志（〜ないつもりだ）の意味を持ちます。","hot":false,"source":"02_古典文法_助動詞.md"},{"id":"k16","theme":"古典文法","title":"助動詞「べし」（推量・意志・可能・当然・命令・適当）","summary":"「べし」は終止形（ラ変型は連体形）接続で、推量・意志・可能・当然・命令・適当の6義があります。「すいかとめて（推量・意志・可能・当然・命令・適当）」の語呂で覚えます。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k17","theme":"古典文法","title":"助動詞「き・けり」（過去）","summary":"「き」「けり」はともに過去を表し連用形に接続します。「き」は自分が直接体験した過去（直接過去）、「けり」は伝聞や気づき（詠嘆）を表します。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k18","theme":"古典文法","title":"助動詞「つ・ぬ」（完了・強意）","summary":"「つ・ぬ」は連用形接続で、完了（〜た・〜てしまった）を表します。下に推量の助動詞を伴うと強意（きっと〜・必ず〜）になり、「つべし」「ぬべし」「てむ」「なむ」の形が代表例です。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k19","theme":"古典文法","title":"助動詞「たり・り」（完了・存続）","summary":"「たり」は連用形、「り」はサ変未然形・四段已然形に接続し、完了・存続（〜ている・〜てある）を表します。「り」の接続は「サ未四已（さみしい）」の語呂で覚えるのが定番で、識別問題で頻出します。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k20","theme":"古典文法","title":"助動詞「なり・たり」（断定）","summary":"断定の「なり」は体言・連体形に接続し「〜である」、「たり」は体言に接続し「〜である」を表します。伝聞推定の「なり」（終止形接続）との識別が頻出で、接続する語の活用形で見分けます。","hot":false,"source":"02_古典文法_助動詞.md"},{"id":"k21","theme":"古典文法","title":"助動詞「なり」（伝聞・推定）","summary":"伝聞推定の「なり」は終止形（ラ変型は連体形）に接続し、「〜という・〜らしい・〜ようだ」の意味です。音や声を根拠とする推定（聴覚推定）が特徴で、断定の「なり」と接続で区別する点が最頻出の識別問題です。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k22","theme":"古典文法","title":"助動詞「めり・らむ・けむ」（推量系）","summary":"「めり」は視覚に基づく推量（〜ように見える）、「らむ」は現在推量（今ごろ〜ているだろう）、「けむ」は過去推量（〜ただろう）です。「らむ」は終止形、「けむ」は連用形接続という接続の違いが識別の決め手になります。","hot":false,"source":"02_古典文法_助動詞.md"},{"id":"k23","theme":"古典文法","title":"助動詞「まし」（反実仮想・ためらいの意志）","summary":"「まし」は未然形接続で、反実仮想（もし〜なら…だろうに）が中心的意味です。「ましかば〜まし」「せば〜まし」「ば〜まし」の構文をとり、事実に反する仮定を表します。","hot":true,"source":"02_古典文法_助動詞.md"},{"id":"k24","theme":"古典文法","title":"助動詞「まほし・たし」（願望）","summary":"「まほし」は未然形、「たし」は連用形に接続し、ともに願望（〜たい）を表します。「まほし」は和文に、「たし」は中世以降に多く用いられます。","hot":false,"source":"02_古典文法_助動詞.md"},{"id":"k25","theme":"古典文法","title":"助動詞「ごとし」（比況）","summary":"「ごとし」は体言・連体形・助詞「が・の」に接続し、比況（〜のようだ・〜と同じだ）を表します。「〜のごとし」の形で例示や比喩に用いられ、漢文訓読調の文章に多く現れます。","hot":false,"source":"02_古典文法_助動詞.md"},{"id":"k26","theme":"古典文法","title":"格助詞「が・の」（主格・連体格・同格・準体格）","summary":"「が・の」は主格（〜が）、連体格（〜の）、同格（〜で）、準体格（〜のもの）の用法を持ちます。特に同格の「の」（例：白き鳥の…をかしげなる）と準体格の「の」（例：我が身一つの〜）の識別が入試で頻出です。","hot":true,"source":"03_古典文法_助詞.md"},{"id":"k27","theme":"古典文法","title":"格助詞「にて・して・より・から」","summary":"「にて」は場所・手段・原因（〜で）、「して」は手段・使役の相手、「より・から」は起点・経由・即時（〜やいなや）・手段を表します。「より」の即時用法（〜するとすぐに）や限定（〜よりほかに）は読解で問われやすい点です。","hot":false,"source":"03_古典文法_助詞.md"},{"id":"k28","theme":"古典文法","title":"接続助詞「ば」（順接の確定・仮定条件）","summary":"接続助詞「ば」は、未然形＋「ば」で順接仮定条件（もし〜なら）、已然形＋「ば」で順接確定条件（〜ので・〜と・〜ところ）を表します。接続する活用形によって意味が真逆になるため、未然形か已然形かの判別が最重要です。","hot":true,"source":"03_古典文法_助詞.md"},{"id":"k29","theme":"古典文法","title":"接続助詞「とも・ど・ども」（逆接条件）","summary":"「とも」は逆接仮定条件（たとえ〜ても）、「ど・ども」は逆接確定条件（〜けれども）を表します。「とも」は終止形（形容詞は連用形）、「ど・ども」は已然形に接続します。","hot":false,"source":"03_古典文法_助詞.md"},{"id":"k30","theme":"古典文法","title":"接続助詞「て・して・で」","summary":"「て・して」は単純接続（〜て）、「で」は打消接続（〜ないで）を表します。「で」は未然形に接続し「〜ずに」と訳す点が重要で、否定の意味を含むことを見落とさないようにします。","hot":true,"source":"03_古典文法_助詞.md"},{"id":"k31","theme":"古典文法","title":"接続助詞「つつ・ながら」","summary":"「つつ」は反復・継続（〜しては・〜し続けて）と動作の並行を表します。「ながら」は並行（〜しながら）と逆接（〜のままで・〜けれども）の意味を持ちます。","hot":false,"source":"03_古典文法_助詞.md"},{"id":"k32","theme":"古典文法","title":"副助詞「だに・すら・さへ」","summary":"「だに」は類推（〜さえ）と最小限の限定（せめて〜だけでも）、「すら」は類推（〜さえ）、「さへ」は添加（〜までも）を表します。「だに」と「さへ」の意味の違い（限定・類推か、添加か）が識別問題で頻出です。","hot":true,"source":"03_古典文法_助詞.md"},{"id":"k33","theme":"古典文法","title":"副助詞「し・しも」（強意）","summary":"「し・しも」は語調を整え強意を表す副助詞で、訳出しないことも多い語です。「しも」は下に打消を伴うと部分否定（必ずしも〜ない）になります。","hot":false,"source":"03_古典文法_助詞.md"},{"id":"k34","theme":"古典文法","title":"係助詞「ぞ・なむ・や・か・こそ」（係り結び）","summary":"係助詞「ぞ・なむ・こそ」は強意、「や・か」は疑問・反語を表し、係り結びを起こします。「ぞ・なむ・や・か」は結びが連体形、「こそ」は已然形になります。","hot":true,"source":"03_古典文法_助詞.md"},{"id":"k35","theme":"古典文法","title":"係助詞「は・も」","summary":"「は」は他と区別する取り立て、「も」は同類・添加・並列を表します。文の主題を示す基本的な係助詞で、係り結びは起こしません。","hot":false,"source":"03_古典文法_助詞.md"},{"id":"k36","theme":"古典文法","title":"終助詞「なむ・ばや・もがな・てしがな」（願望）","summary":"願望を表す終助詞には、他への願望「なむ」（〜してほしい・未然形接続）、自己の願望「ばや」（〜したい）、実現困難な願望「もがな」（〜があればなあ）、「てしがな・にしがな」（〜したいものだ）があります。願望の対象の違いが頻出ポイントです。","hot":true,"source":"03_古典文法_助詞.md"},{"id":"k37","theme":"古典文法","title":"終助詞「な・そ・かな・は・よ」","summary":"「な」は禁止（〜するな）、「な〜そ」は穏やかな禁止（〜してくれるな）、「かな・は・よ」は詠嘆（〜だなあ）を表します。特に「な〜そ」の呼応（副詞「な」と終助詞「そ」で挟む形）の識別が頻出です。","hot":false,"source":"03_古典文法_助詞.md"},{"id":"k38","theme":"古典文法","title":"係り結びの法則（基本）","summary":"係り結びとは、文中に係助詞があると文末（結び）の活用形が変化する法則です。「ぞ・なむ・や・か」があると結びは連体形、「こそ」があると結びは已然形になります。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k39","theme":"古典文法","title":"係り結びの意味（強意・疑問・反語）","summary":"「ぞ・なむ・こそ」は強意（特に訳に表れない強調）、「や・か」は疑問（〜か）または反語（〜だろうか、いや〜ない）を表します。反語は文脈上「否定」の答えを導く点が重要で、疑問か反語かの判別が読解で頻出します。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k40","theme":"古典文法","title":"係り結びの流れ・消滅","summary":"結びとなるはずの語の下にさらに語が続くと、係り結びが完成せず「結びの流れ（消滅）」が起こります。また「こそ〜已然形、」のように已然形で文が終わらず下に続くと逆接（〜けれども）の意味になります。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k41","theme":"古典文法","title":"敬語の種類（尊敬・謙譲・丁寧）","summary":"敬語には3種類あります。尊敬語は動作をする人を高める（給ふ・おはす等）、謙譲語は動作を受ける人を高める（奉る・申す等）、丁寧語は聞き手・読み手を高める（侍り・候ふ）です。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k42","theme":"古典文法","title":"尊敬語の主な語","summary":"主な尊敬語は「給ふ（四段）・おはす・おはします（いらっしゃる）・のたまふ（おっしゃる）・召す（お呼びになる・召し上がる）・大殿籠る（おやすみになる）・思す・おぼしめす（お思いになる）」です。動作主への敬意を表す点を押さえます。","hot":false,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k43","theme":"古典文法","title":"謙譲語の主な語","summary":"主な謙譲語は「奉る・参らす（差し上げる）・申す・聞こゆ（申し上げる）・参る・まうづ（参上する）・まかる・まかづ（退出する）・賜はる（いただく）・侍り（お仕えする）」です。動作の受け手への敬意を表します。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k44","theme":"古典文法","title":"丁寧語の主な語","summary":"主な丁寧語は「侍り・候ふ（さぶらふ／さうらふ）」で、「〜です・〜ます・〜ございます」と訳します。会話文や手紙文で聞き手への敬意を表すのが基本で、「あり・をり」の丁寧語としても用いられます。","hot":false,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k45","theme":"古典文法","title":"「給ふ」の四段活用と下二段活用","summary":"「給ふ」には四段活用（尊敬語：お〜になる）と下二段活用（謙譲語：〜ております）の二つがあります。下二段の「給ふ」は「思ふ・見る・聞く・知る」など知覚動詞に付き会話文で用いられる点が特徴で、識別が頻出です。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k46","theme":"古典文法","title":"二重敬語（最高敬語）","summary":"二重敬語は尊敬語を重ねて最高位の人物への敬意を表す表現です。「せ給ふ・させ給ふ・しめ給ふ」「のたまはす」などが代表例で、天皇・皇后・上皇など最高位の人物に用いられます。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k47","theme":"古典文法","title":"絶対敬語","summary":"絶対敬語は特定の最高位の人物にのみ用いられる敬語です。「奏す」は天皇・上皇に申し上げる、「啓す」は皇后・皇太子・中宮に申し上げる意味です。","hot":true,"source":"04_古典文法_係り結びと敬語.md"},{"id":"k48","theme":"古文単語","title":"あはれなり","summary":"「あはれなり」はしみじみとした情趣を表す語で、「しみじみと心打たれる・趣深い・かわいそうだ」と訳します。喜怒哀楽すべての深い感動に用いられ、平安文学（特に『源氏物語』）の美的理念を示す重要語です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k49","theme":"古文単語","title":"をかし","summary":"「をかし」は明るく知的な美を表す語で、「趣がある・風情がある・興味深い・こっけいだ」と訳します。『枕草子』を代表する美意識で、「あはれ」が情緒的なのに対し「をかし」は理知的・客観的な美を示す点が対比で頻出します。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k50","theme":"古文単語","title":"うつくし","summary":"「うつくし」は「かわいい・いとしい」という意味で、小さいものや幼いものへの愛情を表します。現代語の「美しい」とは異なり、容姿の美ではなく愛らしさを表す点が頻出の注意語です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k51","theme":"古文単語","title":"ありがたし","summary":"「ありがたし」は「めったにない・珍しい・難しい」という意味です。「有り難し」＝存在しがたい、が原義で、現代語の「感謝」の意味はありません。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k52","theme":"古文単語","title":"やさし","summary":"「やさし」は「恥ずかしい・きまりが悪い・つらい」、さらに「優美だ・けなげだ」の意味を持ちます。「身もやせるほどつらい」が原義で、現代語の「優しい（親切）」とは異なる点が要注意です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k53","theme":"古文単語","title":"うし（憂し）","summary":"「うし」は「つらい・いやだ・憂鬱だ」という意味で、自分の身の上を嘆く心情を表します。「つらし」が他者に対する非難を含むのに対し、「うし」は自分の内側に向かう嘆きである点が読解で重要です。","hot":false,"source":"05_古文単語_頻出語.md"},{"id":"k54","theme":"古文単語","title":"いみじ","summary":"「いみじ」は程度のはなはだしさを表す語で、文脈により「ひどく良い・すばらしい」とも「ひどく悪い・恐ろしい」とも訳します。良い意味か悪い意味かを文脈で判断する必要がある点が頻出です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k55","theme":"古文単語","title":"ゆゆし","summary":"「ゆゆし」は「不吉だ・恐れ多い」が原義で、転じて「はなはだしい・すばらしい」の意味にもなります。神聖なものに触れてはならないという畏怖の感情が根底にあり、良悪両方の程度の強さを表します。","hot":false,"source":"05_古文単語_頻出語.md"},{"id":"k56","theme":"古文単語","title":"まめなり","summary":"「まめなり」は「まじめだ・誠実だ・実用的だ」という意味です。「まめまめし」も同様に誠実・実直を表します。","hot":false,"source":"05_古文単語_頻出語.md"},{"id":"k57","theme":"古文単語","title":"つきづきし","summary":"「つきづきし」は「似つかわしい・ふさわしい・調和している」という意味です。『枕草子』の「冬はつとめて」の段で雪や霜と火桶の調和を述べる場面が有名で、調和・適合を表す美的語として頻出します。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k58","theme":"古文単語","title":"おどろく","summary":"「おどろく」は「はっと気づく・目を覚ます」という意味が中心です。現代語の「驚く（びっくりする）」の意味もありますが、「目が覚める・ふと気づく」の意で問われることが多い注意語です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k59","theme":"古文単語","title":"ののしる","summary":"「ののしる」は「大声で騒ぐ・評判になる」という意味です。現代語の「罵る（悪口を言う）」とは異なり、大声を立てて騒ぐ・世間で評判が高いの意で用いられる点が頻出の注意語です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k60","theme":"古文単語","title":"かなし","summary":"「かなし」は「いとしい・かわいい」と「悲しい・切ない」の両義を持ちます。「愛し」と書けば肉親や恋人への深い愛情を、「悲し」と書けば悲哀を表します。","hot":false,"source":"05_古文単語_頻出語.md"},{"id":"k61","theme":"古文単語","title":"あからさまなり","summary":"「あからさまなり」は「ほんの少し・かりそめだ・ちょっと」という意味で、短時間・一時的なさまを表します。現代語の「あからさま（露骨）」とは全く異なる意味であり、誤訳しやすい頻出語です。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k62","theme":"古文単語","title":"やがて","summary":"「やがて」は「そのまま・すぐに」という意味です。現代語の「やがて（しばらくして）」のような時間的隔たりはなく、「そのまま即座に」の意で用いられる点が時間表現の注意語として頻出します。","hot":true,"source":"05_古文単語_頻出語.md"},{"id":"k63","theme":"古文単語","title":"おぼゆ","summary":"「おぼゆ」は「自然に思われる・思い出される・似る」の多義語です。「思ふ」が意図的なのに対し「おぼゆ」は自然にそう感じられる自発の意を含みます。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k64","theme":"古文単語","title":"ときめく","summary":"「ときめく」は「寵愛を受ける・時流に乗って栄える」という意味です。現代語の「胸がときめく」とは異なり、帝などの権力者から特別な寵愛を受けて栄える意で用いられます。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k65","theme":"古文単語","title":"あそぶ","summary":"「あそぶ」は「詩歌・管弦を楽しむ」という意味が中心です。単なる遊戯ではなく、和歌を詠んだり楽器を演奏したりする風雅な遊びを指します。","hot":false,"source":"06_古文単語_多義語と注意語.md"},{"id":"k66","theme":"古文単語","title":"なつかし","summary":"「なつかし」は「心が引かれる・親しみが持てる・慕わしい」という意味です。現代語の「過去を懐かしむ」の意味は薄く、対象に心が引きつけられる愛着の感情を表す点が注意語として頻出します。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k67","theme":"古文単語","title":"こころもとなし","summary":"「こころもとなし」は「待ち遠しい・じれったい・気がかりだ・不安だ」という意味です。待ち望むあまり落ち着かない心情を表し、現代語にはない「待ち遠しさ・じれったさ」のニュアンスが頻出ポイントです。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k68","theme":"古文単語","title":"かたはらいたし","summary":"「かたはらいたし」は「みっともない・気の毒だ・恥ずかしい」という意味です。傍で見ていて心が痛む、の意で、自分にも他人にも用います。","hot":false,"source":"06_古文単語_多義語と注意語.md"},{"id":"k69","theme":"古文単語","title":"いたづらなり","summary":"「いたづらなり」は「むなしい・無駄だ・手持ちぶさただ」という意味です。現代語の「いたずら（悪ふざけ）」とは無関係で、何の役にも立たない・空虚であるさまを表す点が誤訳しやすい頻出語です。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k70","theme":"古文単語","title":"おとなし","summary":"「おとなし」は「大人びている・分別がある・年配だ」という意味です。現代語の「おとなしい（静かで従順）」ではなく、年長で思慮分別があるさまを表します。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k71","theme":"古文単語","title":"さうざうし","summary":"「さうざうし」は「もの足りない・心寂しい」という意味です。あるべきものがなくて物足りない感じを表し、現代語の「騒々しい」とは全く異なります。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k72","theme":"古文単語","title":"あぢきなし","summary":"「あぢきなし」は「どうしようもない・つまらない・道理に合わない」という意味です。思い通りにならず嫌気がさすさまを表し、無常観や諦めの心情を伴って用いられることが多い語です。","hot":false,"source":"06_古文単語_多義語と注意語.md"},{"id":"k73","theme":"古文単語","title":"せうそこ（消息）","summary":"「せうそこ」は「手紙・訪問・取り次ぎを頼むこと」という意味です。現代語の「消息（安否）」よりも広く、便りや訪問、案内を請うことなど人と人との連絡全般を指す点が頻出です。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k74","theme":"古文単語","title":"ゐる（居る・率る）","summary":"「ゐる」は「居る（座る・とまる・存在する）」と「率る（引き連れる）」の二語があります。「率る」は「ゐて行く（連れて行く）・ゐて来（連れて来る）」の形で頻出し、動作の主従関係を読む鍵になります。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k75","theme":"古文単語","title":"はかなし","summary":"「はかなし」は「あっけない・頼りない・むなしい・ちょっとした」という意味です。長続きせずもろいさまを表し、無常観と結びつく語です。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k76","theme":"古文単語","title":"おぼつかなし","summary":"「おぼつかなし」は「ぼんやりしている・気がかりだ・待ち遠しい」という意味です。はっきりせず不安に思う心情を表し、「こころもとなし」と近い意味で用いられます。","hot":false,"source":"06_古文単語_多義語と注意語.md"},{"id":"k77","theme":"古文単語","title":"ふみ（文）","summary":"「ふみ」は「手紙・漢詩文・学問・書物」という意味の多義語です。文脈により「恋文」を指したり「漢学・学問」を指したりします。","hot":true,"source":"06_古文単語_多義語と注意語.md"},{"id":"k78","theme":"文学史","title":"上代（奈良時代）の文学","summary":"上代は奈良時代を中心とする時期で、文字（漢字）による記録が始まりました。歴史書『古事記』『日本書紀』、地誌『風土記』、現存最古の歌集『万葉集』、漢詩集『懐風藻』が成立しました。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k79","theme":"文学史","title":"中古（平安時代）の文学","summary":"中古は平安時代で、仮名文字の発達により女性による仮名文学が花開きました。物語・日記・随筆・歌物語が栄え、『源氏物語』『枕草子』『古今和歌集』など王朝文学の最高峰が生まれました。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k80","theme":"文学史","title":"中世（鎌倉・室町時代）の文学","summary":"中世は鎌倉・室町時代で、武士の台頭と戦乱を背景に無常観が文学の基調となりました。軍記物語『平家物語』、随筆『方丈記』『徒然草』、和歌集『新古今和歌集』、能・狂言・連歌が発達しました。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k81","theme":"文学史","title":"近世（江戸時代）の文学","summary":"近世は江戸時代で、町人文化の発展により庶民的な文学が広まりました。浮世草子（井原西鶴）、俳諧（松尾芭蕉）、人形浄瑠璃・歌舞伎（近松門左衛門）、読本（上田秋成・滝沢馬琴）が栄えました。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k82","theme":"文学史","title":"物語（作り物語・歌物語・歴史物語・軍記物語）","summary":"物語は内容により分類されます。作り物語（虚構：竹取物語・源氏物語）、歌物語（和歌中心：伊勢物語・大和物語）、歴史物語（史実を物語化：大鏡・栄花物語）、軍記物語（合戦記：平家物語・太平記）に分かれます。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k83","theme":"文学史","title":"日記文学","summary":"日記文学は自己の体験や心情を仮名で綴る文学で、平安時代に女性によって発達しました。『土佐日記』（紀貫之・男性が女性に仮託）、『蜻蛉日記』『和泉式部日記』『紫式部日記』『更級日記』が代表作です。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k84","theme":"文学史","title":"随筆","summary":"随筆は見聞や感想を自由に書き綴る散文で、「三大随筆」が頻出です。平安の『枕草子』（清少納言）、鎌倉の『方丈記』（鴨長明）、鎌倉末〜南北朝の『徒然草』（兼好法師）を三大随筆と呼びます。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k85","theme":"文学史","title":"説話文学","summary":"説話文学は民間に伝わる説話を集めた文学です。仏教説話と世俗説話があり、『今昔物語集』（最大の説話集）、『宇治拾遺物語』『十訓抄』『古今著聞集』『発心集』などが代表作です。","hot":false,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k86","theme":"文学史","title":"勅撰和歌集（八代集）","summary":"勅撰和歌集は天皇・上皇の命で編まれた和歌集です。最初の八集を「八代集」と呼び、『古今和歌集』に始まり『新古今和歌集』に至ります。","hot":true,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k87","theme":"文学史","title":"俳諧・連歌","summary":"連歌は和歌の上の句と下の句を複数人で詠み継ぐ文芸で、室町時代に大成しました。そこから滑稽味を加えた俳諧連歌が生まれ、江戸時代に松尾芭蕉が芸術性を高めた「蕉風俳諧」を確立しました。","hot":false,"source":"07_文学史_時代区分とジャンル.md"},{"id":"k88","theme":"文学史","title":"竹取物語","summary":"『竹取物語』は平安初期に成立した、現存最古の作り物語です。作者未詳で、かぐや姫の昇天を描きます。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k89","theme":"文学史","title":"伊勢物語","summary":"『伊勢物語』は平安初期成立の歌物語で、作者未詳です。在原業平とおぼしき「昔男」の一代記を、和歌を中心に約125段で構成します。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k90","theme":"文学史","title":"源氏物語","summary":"『源氏物語』は平安中期、紫式部によって書かれた全54帖の長編物語です。光源氏とその子孫を主人公に、宮廷貴族の恋愛と人生を描きます。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k91","theme":"文学史","title":"枕草子","summary":"『枕草子』は平安中期、清少納言による随筆で、日本最初の随筆とされます。一条天皇の中宮定子に仕えた作者の観察と感想を、「ものづくし（類聚的章段）」「日記的章段」「随想的章段」で綴ります。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k92","theme":"文学史","title":"古今和歌集","summary":"『古今和歌集』は平安前期、醍醐天皇の命で紀貫之らが編纂した最初の勅撰和歌集です。仮名序（紀貫之）と真名序を持ち、七五調・三句切れ・縁語・掛詞を駆使した理知的・技巧的歌風が特徴です。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k93","theme":"文学史","title":"土佐日記","summary":"『土佐日記』は平安前期、紀貫之による日記文学で、最初の仮名日記です。土佐から京へ帰る旅を、作者が女性に仮託して仮名で記しました。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k94","theme":"文学史","title":"大鏡","summary":"『大鏡』は平安後期成立の歴史物語で、作者未詳です。藤原道長の栄華を中心に、大宅世継・夏山繁樹という二人の老人の対話形式（紀伝体）で歴史を語ります。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k95","theme":"文学史","title":"方丈記","summary":"『方丈記』は鎌倉前期、鴨長明による随筆で三大随筆の一つです。「ゆく河の流れは絶えずして…」の冒頭で無常観を表明し、大火・竜巻・飢饉などの天変地異を記録した後、自身の隠遁生活を描きます。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k96","theme":"文学史","title":"徒然草","summary":"『徒然草』は鎌倉末期、兼好法師（吉田兼好）による随筆で三大随筆の一つです。「つれづれなるままに…」の序段で始まり、無常観・処世訓・有職故実・美意識など多彩な内容を約240段で綴ります。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k97","theme":"文学史","title":"平家物語","summary":"『平家物語』は鎌倉時代成立の軍記物語で、作者は信濃前司行長とも伝わります。「祇園精舎の鐘の声、諸行無常の響きあり」で始まり、平家の栄華と滅亡を仏教的無常観で描きます。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k98","theme":"文学史","title":"新古今和歌集","summary":"『新古今和歌集』は鎌倉前期、後鳥羽院の命で藤原定家らが編纂した八代集最後の勅撰集です。本歌取り・体言止め・初句切れ・三句切れ・幽玄・余情を特徴とし、技巧的で象徴的な歌風を確立しました。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k99","theme":"文学史","title":"おくのほそ道","summary":"『おくのほそ道』は江戸前期、松尾芭蕉による俳諧紀行文です。元禄2年、江戸から東北・北陸をめぐり大垣に至る旅を、俳句を交えた格調高い文章で記しました。","hot":true,"source":"08_文学史_代表作品と作者.md"},{"id":"k100","theme":"和歌","title":"五七五七七と句切れ","summary":"和歌（短歌）は「五・七・五・七・七」の三十一音から成り、上から初句・二句・三句・四句・結句と呼びます。意味や調子の切れ目を「句切れ」といい、初句切れ・二句切れ・三句切れなどがあります。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k101","theme":"和歌","title":"枕詞（まくらことば）","summary":"枕詞は特定の語を導く、原則五音の修飾語で、それ自体は訳しません。「ちはやぶる→神」「あしひきの→山」「ひさかたの→光・天」「たらちねの→母」「あをによし→奈良」などが代表例です。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k102","theme":"和歌","title":"序詞（じょことば）","summary":"序詞はある語句を導き出すために置かれる、七音以上の比較的長い修飾表現です。枕詞と違い字数や導く語が一定でなく、その都度作者が創作します。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k103","theme":"和歌","title":"掛詞（かけことば）","summary":"掛詞は同音を利用して一語に二つの意味を持たせる技法です。「まつ（松・待つ）」「あき（秋・飽き）」「ながめ（長雨・眺め）」「よ（夜・世）」「うき（憂き・浮き）」などが頻出で、自然と心情の二重の意味を重ねます。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k104","theme":"和歌","title":"縁語（えんご）","summary":"縁語は一首の中に意味上関連する語を意図的に散りばめ、連想で歌に深みを与える技法です。例えば「糸」に対し「張る・乱る・よる・絶ゆ」、「波」に対し「立つ・寄る・返る」を配します。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k105","theme":"和歌","title":"本歌取り（ほんかどり）","summary":"本歌取りは有名な古歌（本歌）の語句や趣向を意図的に取り入れ、新たな歌を詠む技法です。元の歌を背景に重層的な余情を生み出します。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k106","theme":"和歌","title":"体言止め","summary":"体言止めは結句を名詞（体言）で終える技法で、余情・余韻を残す効果があります。『新古今和歌集』に多く見られ、言い切らないことで読者の想像を誘います。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k107","theme":"和歌","title":"倒置法・対句","summary":"倒置法は語順を入れ替えて強調や余情を生む技法、対句は対応する語句を並べて調子を整える技法です。和歌の表現効果を問う設問で扱われることがあり、強調・印象づけの働きを理解しておくことが大切です。","hot":false,"source":"09_和歌_技法と修辞法.md"},{"id":"k108","theme":"和歌","title":"折句（おりく）・物名（もののな）","summary":"折句は各句の頭に語を一字ずつ詠み込む技法で、『伊勢物語』東下りの「かきつばた」を詠み込んだ歌が有名です。物名（隠し題）は歌の意味とは別に物の名を句中に隠す言葉遊びです。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k109","theme":"和歌","title":"歌枕（うたまくら）","summary":"歌枕は和歌に詠み込まれる名所・地名で、特定のイメージや連想を伴います。「龍田川→紅葉」「吉野→桜・雪」「逢坂の関→逢う」「天の橋立」などが代表例です。","hot":true,"source":"09_和歌_技法と修辞法.md"},{"id":"k110","theme":"和歌","title":"ちはやぶる神代も聞かず竜田川（在原業平）","summary":"在原業平の「ちはやぶる神代も聞かず竜田川からくれなゐに水くくるとは」は、竜田川の紅葉の美を詠んだ歌です。「ちはやぶる」は「神」を導く枕詞で、神代でも聞いたことがないほど紅葉が川を真紅に染める様子を誇張的に讃えています。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k111","theme":"和歌","title":"田子の浦にうち出でて見れば（山部赤人）","summary":"山部赤人の「田子の浦にうち出でて見れば白妙の富士の高嶺に雪は降りつつ」は、富士の雪景色を詠んだ叙景歌です。「白妙の」は「雪」を導く枕詞で、清新で雄大な自然描写が万葉調の特徴を示します。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k112","theme":"和歌","title":"あしびきの山鳥の尾の（柿本人麻呂）","summary":"柿本人麻呂の「あしびきの山鳥の尾のしだり尾の長々し夜をひとりかも寝む」は、独り寝のわびしさを詠んだ歌です。「あしびきの山鳥の尾のしだり尾の」までが「長々し」を導く序詞で、長い夜の孤独を山鳥の長い尾に重ねています。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k113","theme":"和歌","title":"花の色は移りにけりな（小野小町）","summary":"小野小町の「花の色は移りにけりないたづらにわが身世にふるながめせしまに」は、女性の容姿の衰えを花に重ねた歌です。「ふる（経る・降る）」「ながめ（眺め・長雨）」が掛詞で、桜の色あせと我が身の老いを二重に詠む技巧が頻出です。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k114","theme":"和歌","title":"花さそふ嵐の庭の（藤原公経／入道前太政大臣）","summary":"「花さそふ嵐の庭の雪ならでふりゆくものはわが身なりけり」は、散る桜を雪に見立て、老いゆく身を嘆く歌です。「ふり（降り・古り）」が掛詞で、散る花びらと自分が年老いていくことを重ねています。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k115","theme":"和歌","title":"立ち別れいなばの山の（在原行平）","summary":"在原行平の「立ち別れいなばの山の峰に生ふるまつとし聞かば今帰り来む」は、別れの際の再会を願う歌です。「いなば（往なば・因幡）」「まつ（松・待つ）」が掛詞で、地名と心情を巧みに重ねた掛詞の代表例として頻出します。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k116","theme":"和歌","title":"古今和歌集の歌風","summary":"『古今和歌集』の歌風は、掛詞・縁語を駆使した理知的・技巧的なものです。七五調・三句切れが多く、優美で繊細な「たをやめぶり」と評されます。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k117","theme":"和歌","title":"新古今和歌集の歌風","summary":"『新古今和歌集』の歌風は、本歌取り・体言止め・初句切れ・三句切れを特徴とし、幽玄・余情を重んじる象徴的・絵画的なものです。藤原定家・西行・式子内親王らが代表歌人で、技巧の頂点とされる点が頻出です。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k118","theme":"和歌","title":"万葉集の歌風","summary":"『万葉集』の歌風は、素朴で力強く率直な「ますらをぶり」と評されます。五七調・二句切れ・四句切れが多く、額田王・柿本人麻呂・山上憶良・大伴家持らが代表歌人です。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k119","theme":"和歌","title":"三大歌集の比較","summary":"万葉・古今・新古今を「三大歌集」と呼びます。万葉＝ますらをぶり・五七調・素朴、古今＝たをやめぶり・七五調・技巧、新古今＝幽玄余情・本歌取り・体言止め、と各集の歌風と特徴語を対比して覚えるのが頻出の整理ポイントです。","hot":true,"source":"10_和歌_百人一首と勅撰集.md"},{"id":"k120","theme":"和歌","title":"和歌の内容読解の基本手順","summary":"和歌読解はまず句切れと修辞（掛詞・序詞）を見抜き、次に詠み手の置かれた状況と心情を文脈から読み取ります。地の文（詞書）に詠歌の事情が書かれることが多く、詞書と和歌を結びつけて解釈するのが鉄則です。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k121","theme":"和歌","title":"贈答歌の読解","summary":"贈答歌は男女や友人間でやり取りされる歌で、相手の歌の語句を受けて返す「返歌」の技法が重要です。返歌では相手の歌の語句・趣向を踏まえて応じるのが約束で、二首の関係を読み解く問題が頻出します。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k122","theme":"和歌","title":"袖と涙の連想","summary":"和歌では「袖」が涙でぬれるものとして頻出します。「袖の涙」「袖をしぼる」「袖の露」は深い悲しみや恋の苦しみを表す決まり文句です。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k123","theme":"和歌","title":"月・露・夢が表す心情","summary":"月は孤独・物思い・遠い人への思慕、露は，はかなさ・涙・短命、夢は恋しい人との逢瀬や現実のはかなさを象徴します。これらの景物が表す定型的な心情を知ることで、叙景の奥にある心情を読み取れます。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k124","theme":"和歌","title":"「あき」の掛詞と恋の歌","summary":"恋の歌では「あき（秋・飽き）」の掛詞が頻出します。秋の訪れに男の心変わり（飽き）を重ね、恋の終わりや嘆きを表現します。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k125","theme":"和歌","title":"旅と望郷の歌","summary":"旅の歌では故郷や都への思慕（望郷）が主題となります。『伊勢物語』東下りの「唐衣きつつなれにしつましあればはるばる来ぬる旅をしぞ思ふ」は、「かきつばた」の折句と「つま（妻・褄）」「はるばる（張る・遥々）」の掛詞で望郷を詠む頻出歌です。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k126","theme":"和歌","title":"西行の歌と無常観","summary":"西行の「願はくは花の下にて春死なむそのきさらぎの望月のころ」は、桜の下での往生を願う歌です。出家して諸国を旅した西行は、花（桜）と月を愛し無常観を詠みました。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k127","theme":"和歌","title":"式子内親王の忍ぶ恋","summary":"式子内親王の「玉の緒よ絶えなば絶えねながらへば忍ぶることの弱りもぞする」は、秘めた恋の激情を詠んだ歌です。「玉の緒（命）」が絶えるなら絶えてしまえ、生き永らえれば恋を隠す力が弱ってしまう、という切実な心情が頻出します。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k128","theme":"和歌","title":"時代背景 ― 平安貴族の恋愛","summary":"平安貴族の恋愛は、男が女のもとに通う「通い婚」が基本でした。男はまず和歌を贈り、女が返歌で応じることで関係が進みます。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k129","theme":"和歌","title":"時代背景 ― 出家と隠遁","summary":"中世には世の無常を感じて出家・隠遁する人が多く、和歌にも無常観が色濃く反映されました。西行・鴨長明・兼好らの隠者文学が代表で、俗世を離れた境地から自然や人生を見つめる視点が和歌・随筆に共通する点が頻出です。","hot":true,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k130","theme":"和歌","title":"屏風歌・歌合の文化","summary":"平安期には屏風絵に添える「屏風歌」や、左右に分かれて歌の優劣を競う「歌合」が盛んでした。題に応じて詠む「題詠」が発達し、技巧的な歌が生まれました。","hot":false,"source":"11_和歌_入試頻出歌と読解.md"},{"id":"k131","theme":"和歌","title":"柿本人麻呂","summary":"柿本人麻呂は『万葉集』を代表する宮廷歌人で、「歌聖」と称されます。長歌に優れ、荘重で格調高い枕詞・序詞を駆使した雄大な歌風が特徴です。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k132","theme":"和歌","title":"山上憶良","summary":"山上憶良は『万葉集』の歌人で、社会的・人間的な主題を詠んだ点が特徴です。「貧窮問答歌」で貧しい民の苦しみを、「子等を思ふ歌」で子への愛を詠みました。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k133","theme":"和歌","title":"紀貫之","summary":"紀貫之は『古今和歌集』の撰者の中心で、仮名序を執筆しました。理知的・技巧的な古今調を代表し、『土佐日記』の作者でもあります。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k134","theme":"和歌","title":"小野小町","summary":"小野小町は六歌仙・三十六歌仙の一人で、『古今和歌集』を代表する女性歌人です。夢・恋・容姿の衰えを情熱的かつ繊細に詠み、絶世の美女としても伝説化されました。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k135","theme":"和歌","title":"在原業平","summary":"在原業平は六歌仙の一人で、『伊勢物語』の主人公「昔男」のモデルとされます。情熱的で奔放な恋の歌を詠み、技巧よりも心情の率直さを重んじた歌風が特徴です。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k136","theme":"和歌","title":"六歌仙","summary":"六歌仙は『古今和歌集』仮名序で紀貫之が論評した六人の歌人です。在原業平・小野小町・僧正遍昭・喜撰法師・文屋康秀・大友黒主を指します。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k137","theme":"和歌","title":"西行","summary":"西行は平安末〜鎌倉初期の歌人で、武士の身分を捨てて出家し諸国を旅しました。桜と月を愛し、無常観と自然への深い感動を平明に詠みました。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k138","theme":"和歌","title":"藤原定家","summary":"藤原定家は『新古今和歌集』の撰者の一人で、『小倉百人一首』の撰者でもあります。本歌取りや幽玄・有心を理論化し、技巧的で象徴的な新古今調を主導しました。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k139","theme":"和歌","title":"式子内親王","summary":"式子内親王は『新古今和歌集』を代表する女性歌人で、後白河天皇の皇女です。賀茂斎院を務めた経歴を持ち、秘めた恋（忍ぶ恋）や孤独を繊細かつ激情的に詠みました。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k140","theme":"和歌","title":"後鳥羽院","summary":"後鳥羽院は『新古今和歌集』の編纂を命じた上皇で、自らも優れた歌人でした。和歌所を設置して歌壇を主導し、承久の乱で隠岐に流されました。","hot":true,"source":"12_和歌_歌人と歌風.md"},{"id":"k141","theme":"和歌","title":"三十六歌仙","summary":"三十六歌仙は、藤原公任が『三十六人撰』で選んだ和歌の名人三十六人です。柿本人麻呂・紀貫之・在原業平・小野小町・伊勢・大伴家持らが含まれます。","hot":false,"source":"12_和歌_歌人と歌風.md"},{"id":"k142","theme":"作品理解","title":"源氏物語の構成","summary":"『源氏物語』は全54帖で、紫式部が平安中期に著しました。光源氏の誕生から栄華を描く第一部、源氏の苦悩と紫の上の死までの第二部、源氏死後の薫・匂宮を描く第三部（宇治十帖）の三部構成とされます。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k143","theme":"作品理解","title":"光源氏","summary":"光源氏は物語の主人公で、桐壺帝の第二皇子です。容姿・才能ともに優れ「光る君」と呼ばれますが、臣下に降下します。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k144","theme":"作品理解","title":"桐壺の巻と桐壺更衣","summary":"「桐壺」の巻は物語の発端で、光源氏の母・桐壺更衣を描きます。帝の寵愛を一身に受けた更衣は、他の妃たちの嫉妬の中で源氏を産み、まもなく病死します。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k145","theme":"作品理解","title":"藤壺","summary":"藤壺は桐壺帝の后で、亡き桐壺更衣に生き写しとされる女性です。光源氏が思慕し続けた相手で、源氏との間に不義の子（後の冷泉帝）をもうけます。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k146","theme":"作品理解","title":"紫の上","summary":"紫の上は藤壺の姪で、幼い頃に源氏に見出され引き取られ理想の女性として育てられました。源氏の正妻格として長く連れ添いますが、女三の宮の降嫁により苦悩し、先立って亡くなります。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k147","theme":"作品理解","title":"若紫の巻","summary":"「若紫」の巻は、源氏が幼い紫の上（若紫）と出会う場面を描きます。北山で病気療養中の源氏が、藤壺に面影の似た少女を垣間見て心引かれます。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k148","theme":"作品理解","title":"六条御息所と物の怪","summary":"六条御息所は教養高い貴婦人ですが、源氏への嫉妬から生霊・死霊となり、夕顔・葵の上・紫の上を苦しめます。「葵」の巻での葵の上の死は物の怪の代表的場面です。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k149","theme":"作品理解","title":"主要な女性たちの関係","summary":"源氏をめぐる女性には、夕顔・空蝉・末摘花・明石の君・花散里・朧月夜・女三の宮らがいます。それぞれ身分や性格が描き分けられ、明石の君が産んだ娘は後に中宮となります。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k150","theme":"作品理解","title":"宇治十帖","summary":"宇治十帖は第三部にあたり、源氏の死後を描きます。源氏の子とされる薫（実は柏木の子）と孫の匂宮が、宇治の姫君・大君・中の君・浮舟をめぐって織りなす恋の物語です。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k151","theme":"作品理解","title":"もののあはれ","summary":"『源氏物語』の主題は「もののあはれ」とされ、江戸時代の本居宣長が『源氏物語玉の小櫛』で論じました。物事に触れて自然にわき起こるしみじみとした情趣を指し、源氏物語の美的理念として頻出する重要概念です。","hot":true,"source":"13_頻出作品_源氏物語.md"},{"id":"k152","theme":"作品理解","title":"枕草子の作者と成立","summary":"『枕草子』は清少納言が平安中期に著した日本最初の随筆です。作者は一条天皇の中宮定子に女房として仕えました。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k153","theme":"作品理解","title":"枕草子の三つの章段","summary":"『枕草子』は内容から三種に分類されます。「ものはづくし（類聚的章段）」（例：山は・虫は）、宮廷生活を回想する「日記的章段」、自然や人生への感想を述べる「随想的章段」です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k154","theme":"作品理解","title":"「春はあけぼの」の段","summary":"冒頭「春はあけぼの」の段は、四季それぞれの最も趣深い時と情景を述べた随想的章段です。春は明け方、夏は夜、秋は夕暮れ、冬は早朝（つとめて）を挙げます。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k155","theme":"作品理解","title":"枕草子の美意識「をかし」","summary":"『枕草子』を貫く美意識は「をかし」で、明るく知的で客観的な美を表します。対象を鋭く観察し、理知的に「趣がある・興味深い」と捉える態度が特徴です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k156","theme":"作品理解","title":"徒然草の作者と成立","summary":"『徒然草』は兼好法師（吉田兼好・卜部兼好）が鎌倉末期に著した随筆です。作者は和歌四天王の一人で、出家して隠遁生活を送りました。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k157","theme":"作品理解","title":"徒然草の内容の多様性","summary":"『徒然草』は約240段から成り、内容は無常観・処世訓・有職故実・自然観・芸道論・説話など多岐にわたります。一貫したテーマはなく、折に触れての感想を自由に記した点が特徴です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k158","theme":"作品理解","title":"「神無月のころ」の段","summary":"「神無月のころ」の段は、閑居の僧の庵を訪ねた話です。趣のある庵に感心していると、大きな柑子の木が厳重に囲ってあるのを見て興ざめする、という教訓的逸話です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k159","theme":"作品理解","title":"「仁和寺にある法師」の段","summary":"「仁和寺にある法師」の段は、石清水八幡宮を参詣した法師が、麓の付属の社だけを拝んで本宮（山上）を拝まずに帰った失敗譚です。「少しのことにも先達はあらまほしきことなり」と結ばれ、教訓を説く頻出段です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k160","theme":"作品理解","title":"徒然草の無常観と美意識","summary":"『徒然草』は中世的無常観を基調としつつ、「花は盛りに、月は隈なきをのみ見るものかは」のように、完全でないもの・移ろいゆくものに美を見出す価値観を示します。不完全の美・余情を尊ぶ中世的美意識が頻出です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k161","theme":"作品理解","title":"枕草子と徒然草の比較","summary":"両作は三大随筆ですが、成立時代と美意識が異なります。『枕草子』は平安・宮廷的・「をかし」の明るい美、『徒然草』は鎌倉末・隠者的・無常観に基づく美です。","hot":true,"source":"14_頻出作品_枕草子と徒然草.md"},{"id":"k162","theme":"作品理解","title":"竹取物語の内容","summary":"『竹取物語』は、竹から生まれたかぐや姫が五人の貴公子と帝の求婚を退け、月へ昇天する物語です。五人の求婚者にはそれぞれ難題が課され失敗します。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k163","theme":"作品理解","title":"伊勢物語「東下り」","summary":"『伊勢物語』の「東下り」は、都を離れた「昔男（業平）」が東国へ下る道中を描きます。三河の八橋で「かきつばた」を折句に詠み、隅田川では都鳥に都への思いを託します。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k164","theme":"作品理解","title":"伊勢物語「筒井筒」","summary":"『伊勢物語』の「筒井筒」は、幼なじみの男女が成長して結ばれる話です。井戸の周りで背くらべをした二人が和歌を贈り合って夫婦になります。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k165","theme":"作品理解","title":"土佐日記の内容","summary":"『土佐日記』は紀貫之が土佐国司の任を終え京へ帰る55日間の船旅を、女性に仮託して仮名で記した日記です。任地で亡くした娘への哀惜が全編を貫きます。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k166","theme":"作品理解","title":"更級日記の内容","summary":"『更級日記』は菅原孝標女による回想録で、物語（特に源氏物語）にあこがれた少女時代から晩年までを綴ります。東国から上京し物語に夢中になった日々を回想し、信仰に傾く晩年に至ります。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k167","theme":"作品理解","title":"大鏡の内容と形式","summary":"『大鏡』は藤原道長の栄華を中心に、大宅世継と夏山繁樹という二人の老人の対話形式で歴史を語る歴史物語です。批判精神を含む「鏡物」の代表で、紀伝体をとります。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k168","theme":"作品理解","title":"方丈記の無常観","summary":"『方丈記』は鴨長明が無常観を主題に著した随筆です。「ゆく河の流れは絶えずして、しかももとの水にあらず」の冒頭で世の無常を説き、五大災厄を記録した後、方丈の庵での閑居を描きます。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k169","theme":"作品理解","title":"平家物語の無常観","summary":"『平家物語』は平家一門の栄華と滅亡を仏教的無常観で描く軍記物語です。「祇園精舎の鐘の声、諸行無常の響きあり。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k170","theme":"作品理解","title":"平家物語「敦盛の最期」","summary":"『平家物語』の「敦盛の最期」は、熊谷直実が我が子ほどの年若い平敦盛を討つ場面です。直実は敦盛を助けたいと思いながらも討たざるを得ず、武士の無常を痛感して出家を志します。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k171","theme":"作品理解","title":"おくのほそ道","summary":"『おくのほそ道』は松尾芭蕉の俳諧紀行文で、「月日は百代の過客にして、行きかふ年もまた旅人なり」で始まります。各地で名句を詠み、「夏草や兵どもが夢の跡」「閑さや岩にしみ入る蝉の声」などが有名です。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k172","theme":"作品理解","title":"今昔物語集","summary":"『今昔物語集』は平安後期成立の日本最大の説話集で、作者未詳です。天竺（インド）・震旦（中国）・本朝（日本）の三部に分かれ、各話が「今は昔」で始まります。","hot":true,"source":"15_頻出作品_その他の頻出作品.md"},{"id":"k173","theme":"和歌","title":"旧暦（陰暦）と季節のずれ","summary":"平安時代は太陰太陽暦（旧暦）を用い、現在の暦より約1〜2か月早く季節が進みます。一月〜三月が春、四月〜六月が夏、七月〜九月が秋、十月〜十二月が冬です。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k174","theme":"和歌","title":"月の異名","summary":"和歌では月を異名で詠みます。睦月（一月）・如月（二月）・弥生（三月）・卯月（四月）・皐月（五月）・水無月（六月）・文月（七月）・葉月（八月）・長月（九月）・神無月（十月）・霜月（十一月）・師走（十二月）です。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k175","theme":"和歌","title":"通い婚（妻問婚）","summary":"平安貴族の結婚は、男が女の家に通う「通い婚」が基本で、一夫多妻でした。男が三夜続けて通うと結婚が成立します。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k176","theme":"和歌","title":"後朝（きぬぎぬ）の文","summary":"男女が一夜を共にした翌朝、男が帰宅後すぐに女へ送る手紙を「後朝の文」といいます。早く届くほど愛情が深いとされ、和歌が添えられました。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k177","theme":"和歌","title":"垣間見（かいまみ）","summary":"男が物のすき間から女性の姿をのぞき見ることを「垣間見」といい、恋の始まりのきっかけになりました。当時、貴族の女性は親兄弟以外に姿を見せないのが普通で、垣間見によって恋心が芽生えます。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k178","theme":"和歌","title":"物忌み（ものいみ）と方違え（かたたがえ）","summary":"「物忌み」は不吉な日に身を慎んで家に籠もること、「方違え」は目的地が縁起の悪い方角のとき別の家を経由する習慣です。これらが原因で男女が会えなかったり思わぬ出会いが生じたりします。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k179","theme":"和歌","title":"夢と魂・恋の俗信","summary":"当時、夢に人が現れるのは相手が自分を強く思っているからだ、という俗信がありました。「思ひつつ寝ればや人の見えつらむ」（小野小町）のように、夢を恋の証と捉えます。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k180","theme":"和歌","title":"出家と「世を捨つ」","summary":"俗世を離れて仏門に入ることを「出家・遁世」といい、和歌では「世を背く」「世を捨つ」「世を厭ふ」と表現されます。失恋・死別・無常感が出家の動機となります。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k181","theme":"和歌","title":"賀茂祭（葵祭）と斎院・斎宮","summary":"賀茂祭（葵祭）は平安京最大の祭礼で、単に「祭」といえばこれを指しました。賀茂神社に奉仕する未婚の皇女を斎院、伊勢神宮に仕える皇女を斎宮といいます。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k182","theme":"和歌","title":"七夕・重陽などの節句","summary":"五節句は和歌の格好の題材です。七夕（七月七日）は牽牛・織女の年一度の逢瀬で恋歌に、重陽（九月九日）は菊で長寿を祝う宴に詠まれます。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k183","theme":"和歌","title":"服喪と喪服の色","summary":"近親者が亡くなると一定期間喪に服し、喪服には鈍色（にびいろ＝濃い灰色）を着ました。和歌で「鈍色の衣」「藤衣（喪服）」が出れば死別・哀傷の場面と判断できます。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"},{"id":"k184","theme":"和歌","title":"官位・除目と「身の沈み」","summary":"貴族にとって官位・昇進は重大関心事で、人事を決める儀式を「除目（じもく）」といいます。望む官職に就けない不遇を「身の沈み」「数ならぬ身」と嘆く歌が多く詠まれました。","hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md"}];
window.QUIZ_DATA = [{"id":"q1","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「動詞の活用は全部で9種類あります。「四段・上一段・上二段・下一段・下二段・カ変・サ変・ナ変・ラ変」です。」","answer":"動詞の活用の種類","accept":["動詞の活用の種類"],"hot":true,"source":"01_古典文法_用言の活用.md","choices":["動詞の活用の種類","四段活用","係り結びの法則"]},{"id":"q2","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は「未然形・連用形・終止形・連体形・已然形・命令形」の6つです。未然形は打消や推量に、連用形は中止や過去に、連体形は体言や係り結びに、已然形は逆接や係り結び（こそ）に接続します。」","answer":"活用形","accept":["活用形"],"hot":true,"source":"01_古典文法_用言の活用.md","choices":["助動詞「ず」","活用形","助動詞「む・むず」"]},{"id":"q3","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は、ア・イ・ウ・エの四つの段にわたって活用する動詞です。「書く（書か・書き・書く・書く・書け・書け）」が代表例で、最も語数が多い活用です。」","answer":"四段活用","accept":["四段活用"],"hot":false,"source":"01_古典文法_用言の活用.md","choices":["接続助詞「とも・ど・ども」","動詞の活用の種類","四段活用"]},{"id":"q4","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は、イ段のみで活用する動詞で語数が少なく暗記対象です。「干る・射る・鋳る・着る・似る・煮る・見る・居る・率る」などが該当し、「ひいきにみゐる（贔屓に見入る）」の語呂で覚えます。」","answer":"上一段活用","accept":["上一段活用"],"hot":true,"source":"01_古典文法_用言の活用.md","choices":["絶対敬語","丁寧語の主な語","上一段活用"]},{"id":"q5","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は、エ段のみで活用し、「蹴る」一語のみが該当します。「蹴（け）・蹴（け）・蹴る・蹴る・蹴れ・蹴よ」と活用します。」","answer":"下一段活用","accept":["下一段活用"],"hot":true,"source":"01_古典文法_用言の活用.md","choices":["変格活用","下一段活用","接続助詞「て・して・で」"]},{"id":"q6","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】はイ・ウの二段（過ぐ・落つなど）、【　　　】はウ・エの二段（受く・捨つなど）で活用します。【　　　】は現代語の下一段にあたる動詞が多く、未然形が「エ段＋ず（受けず）」なら【　　　】、「イ段＋ず（過ぎず）」なら【　　　】と見分けます。」","answer":"上二段活用・下二段活用","accept":["上二段活用・下二段活用"],"hot":false,"source":"01_古典文法_用言の活用.md","choices":["助動詞「まし」","助動詞「なり」","上二段活用・下二段活用"]},{"id":"q7","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は不規則な活用で語数が限られます。カ変は「来（く）」一語、サ変は「す・おはす」、ナ変は「死ぬ・往（い）ぬ」、ラ変は「あり・をり・侍り・いますがり」です。」","answer":"変格活用","accept":["変格活用"],"hot":true,"source":"01_古典文法_用言の活用.md","choices":["係り結びの法則","助動詞「む・むず」","変格活用"]},{"id":"q8","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「形容詞にはク活用とシク活用の2種類があります。「なし（ク活用）」「うつくし（シク活用）」のように、連用形に「なる」を付けて「〜くなる」ならク活用、「〜しくなる」ならシク活用と見分けます。」","answer":"形容詞の活用","accept":["形容詞の活用"],"hot":true,"source":"01_古典文法_用言の活用.md","choices":["係助詞「は・も」","終助詞「なむ・ばや・もがな・てしがな」","形容詞の活用"]},{"id":"q9","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「形容動詞にはナリ活用とタリ活用があります。「静かなり（ナリ活用）」は和文に、「堂々たり（タリ活用）」は漢文訓読調の文章に多く用いられます。」","answer":"形容動詞の活用","accept":["形容動詞の活用"],"hot":false,"source":"01_古典文法_用言の活用.md","choices":["形容動詞の活用","助動詞「まほし・たし」","丁寧語の主な語"]},{"id":"q10","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は発音しやすくするために語形が変化する現象です。イ【　　　】（書きて→書いて）、ウ【　　　】（思ひて→思うて）、撥【　　　】（飛びて→飛んで）、促【　　　】（取りて→取つて）の4種類があります。」","answer":"音便","accept":["音便"],"hot":false,"source":"01_古典文法_用言の活用.md","choices":["接続助詞「て・して・で」","形容動詞の活用","音便"]},{"id":"q11","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は四段・ナ変・ラ変の未然形に「る」、それ以外の未然形に【　　　】が付きます。意味は受身・尊敬・自発・可能の4つです。」","answer":"助動詞「る・らる」","accept":["助動詞「る・らる」","助動詞る・らる","る・らる"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["接続助詞「つつ・ながら」","謙譲語の主な語","助動詞「る・らる」"]},{"id":"q12","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は使役（〜せる）と尊敬（〜なさる）の意味を持ちます。下に尊敬語を伴うとき（例：せ給ふ）は尊敬の二重敬語になることが多く、伴わないときは使役と判断します。」","answer":"助動詞「す・さす・しむ」","accept":["助動詞「す・さす・しむ」","助動詞す・さす・しむ","す・さす・しむ"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["助動詞「す・さす・しむ」","終助詞「なむ・ばや・もがな・てしがな」","「給ふ」の四段活用と下二段活用"]},{"id":"q13","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「ず」は打消（〜ない）の意味で、活用語の未然形に接続します。「ず・ず・ず／ぬ・ね」の系列と「ざら・ざり・ざる・ざれ」の系列の二系統で活用する点に注意が必要です。」","answer":"助動詞「ず」","accept":["助動詞「ず」","助動詞ず","ず"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["助動詞「ず」","下一段活用","四段活用"]},{"id":"q14","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「む（ん）」は未然形接続で、推量・意志・適当・勧誘・仮定・婉曲の6つの意味があります。主語が一人称なら意志、二人称なら勧誘・適当、三人称なら推量と、主語の人称で意味を判断するのが基本です。」","answer":"助動詞「む・むず」","accept":["助動詞「む・むず」","助動詞む・むず","む・むず"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["助動詞「き・けり」","係り結びの意味","助動詞「む・むず」"]},{"id":"q15","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「じ」は未然形接続で、「む」の打消にあたります。打消推量（〜ないだろう）と打消意志（〜ないつもりだ）の意味を持ちます。」","answer":"助動詞「じ」","accept":["助動詞「じ」","助動詞じ","じ"],"hot":false,"source":"02_古典文法_助動詞.md","choices":["助動詞「じ」","助動詞「つ・ぬ」","敬語の種類"]},{"id":"q16","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は終止形（ラ変型は連体形）接続で、推量・意志・可能・当然・命令・適当の6義があります。「すいかとめて（推量・意志・可能・当然・命令・適当）」の語呂で覚えます。」","answer":"助動詞「べし」","accept":["助動詞「べし」","助動詞べし","べし"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["動詞の活用の種類","助動詞「ごとし」","助動詞「べし」"]},{"id":"q17","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「き」【　　　】はともに過去を表し連用形に接続します。「き」は自分が直接体験した過去（直接過去）、【　　　】は伝聞や気づき（詠嘆）を表します。」","answer":"助動詞「き・けり」","accept":["助動詞「き・けり」","助動詞き・けり","き・けり"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["上一段活用","助動詞「き・けり」","終助詞「なむ・ばや・もがな・てしがな」"]},{"id":"q18","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は連用形接続で、完了（〜た・〜てしまった）を表します。下に推量の助動詞を伴うと強意（きっと〜・必ず〜）になり、「つべし」「ぬべし」「てむ」「なむ」の形が代表例です。」","answer":"助動詞「つ・ぬ」","accept":["助動詞「つ・ぬ」","助動詞つ・ぬ","つ・ぬ"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["丁寧語の主な語","助動詞「つ・ぬ」","接続助詞「とも・ど・ども」"]},{"id":"q19","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は連用形、「り」はサ変未然形・四段已然形に接続し、完了・存続（〜ている・〜てある）を表します。「り」の接続は「サ未四已（さみしい）」の語呂で覚えるのが定番で、識別問題で頻出します。」","answer":"助動詞「たり・り」","accept":["助動詞「たり・り」","助動詞たり・り","たり・り"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["係り結びの法則","形容詞の活用","助動詞「たり・り」"]},{"id":"q20","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「断定の【　　　】は体言・連体形に接続し「〜である」、【　　　】は体言に接続し「〜である」を表します。伝聞推定の【　　　】（終止形接続）との識別が頻出で、接続する語の活用形で見分けます。」","answer":"助動詞「なり・たり」","accept":["助動詞「なり・たり」","助動詞なり・たり","なり・たり"],"hot":false,"source":"02_古典文法_助動詞.md","choices":["助動詞「なり・たり」","助動詞「ず」","係助詞「ぞ・なむ・や・か・こそ」"]},{"id":"q21","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「伝聞推定の【　　　】は終止形（ラ変型は連体形）に接続し、「〜という・〜らしい・〜ようだ」の意味です。音や声を根拠とする推定（聴覚推定）が特徴で、断定の【　　　】と接続で区別する点が最頻出の識別問題です。」","answer":"助動詞「なり」","accept":["助動詞「なり」","助動詞なり","なり"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["助動詞「む・むず」","助動詞「なり」","接続助詞「て・して・で」"]},{"id":"q22","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は視覚に基づく推量（〜ように見える）、【　　　】は現在推量（今ごろ〜ているだろう）、【　　　】は過去推量（〜ただろう）です。【　　　】は終止形、【　　　】は連用形接続という接続の違いが識別の決め手になります。」","answer":"助動詞「めり・らむ・けむ」","accept":["助動詞「めり・らむ・けむ」","助動詞めり・らむ・けむ","めり・らむ・けむ"],"hot":false,"source":"02_古典文法_助動詞.md","choices":["形容詞の活用","格助詞「が・の」","助動詞「めり・らむ・けむ」"]},{"id":"q23","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は未然形接続で、反実仮想（もし〜なら…だろうに）が中心的意味です。「【　　　】かば〜【　　　】」「せば〜【　　　】」「ば〜【　　　】」の構文をとり、事実に反する仮定を表します。」","answer":"助動詞「まし」","accept":["助動詞「まし」","助動詞まし","まし"],"hot":true,"source":"02_古典文法_助動詞.md","choices":["助動詞「なり」","助動詞「まし」","形容詞の活用"]},{"id":"q24","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は未然形、【　　　】は連用形に接続し、ともに願望（〜たい）を表します。【　　　】は和文に、【　　　】は中世以降に多く用いられます。」","answer":"助動詞「まほし・たし」","accept":["助動詞「まほし・たし」","助動詞まほし・たし","まほし・たし"],"hot":false,"source":"02_古典文法_助動詞.md","choices":["丁寧語の主な語","活用形","助動詞「まほし・たし」"]},{"id":"q25","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は体言・連体形・助詞「が・の」に接続し、比況（〜のようだ・〜と同じだ）を表します。「〜の【　　　】」の形で例示や比喩に用いられ、漢文訓読調の文章に多く現れます。」","answer":"助動詞「ごとし」","accept":["助動詞「ごとし」","助動詞ごとし","ごとし"],"hot":false,"source":"02_古典文法_助動詞.md","choices":["助動詞「ごとし」","副助詞「だに・すら・さへ」","助動詞「す・さす・しむ」"]},{"id":"q26","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は主格（〜が）、連体格（〜の）、同格（〜で）、準体格（〜のもの）の用法を持ちます。特に同格の「の」（例：白き鳥の…をかしげなる）と準体格の「の」（例：我が身一つの〜）の識別が入試で頻出です。」","answer":"格助詞「が・の」","accept":["格助詞「が・の」","格助詞が・の","が・の"],"hot":true,"source":"03_古典文法_助詞.md","choices":["敬語の種類","助動詞「なり」","格助詞「が・の」"]},{"id":"q27","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は場所・手段・原因（〜で）、【　　　】は手段・使役の相手、「【　　　】・【　　　】」は起点・経由・即時（〜やいなや）・手段を表します。【　　　】の即時用法（〜するとすぐに）や限定（〜【　　　】ほかに）は読解で問われやすい点です。」","answer":"格助詞「にて・して・より・から」","accept":["格助詞「にて・して・より・から」","格助詞にて・して・より・から","にて・して・より・から"],"hot":false,"source":"03_古典文法_助詞.md","choices":["上一段活用","格助詞「が・の」","格助詞「にて・して・より・から」"]},{"id":"q28","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は、未然形＋「ば」で順接仮定条件（もし〜なら）、已然形＋「ば」で順接確定条件（〜ので・〜と・〜ところ）を表します。接続する活用形によって意味が真逆になるため、未然形か已然形かの判別が最重要です。」","answer":"接続助詞「ば」","accept":["接続助詞「ば」","接続助詞ば","ば"],"hot":true,"source":"03_古典文法_助詞.md","choices":["終助詞「な・そ・かな・は・よ」","接続助詞「ば」","係助詞「は・も」"]},{"id":"q29","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は逆接仮定条件（たとえ〜ても）、「ど・【　　　】」は逆接確定条件（〜けれ【　　　】）を表します。【　　　】は終止形（形容詞は連用形）、「ど・【　　　】」は已然形に接続します。」","answer":"接続助詞「とも・ど・ども」","accept":["接続助詞「とも・ど・ども」","接続助詞とも・ど・ども","とも・ど・ども"],"hot":false,"source":"03_古典文法_助詞.md","choices":["接続助詞「とも・ど・ども」","助動詞「ず」","助動詞「ごとし」"]},{"id":"q30","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「て・【　　　】」は単純接続（〜て）、「で」は打消接続（〜ないで）を表します。「で」は未然形に接続し「〜ずに」と訳す点が重要で、否定の意味を含むことを見落とさないようにします。」","answer":"接続助詞「て・して・で」","accept":["接続助詞「て・して・で」","接続助詞て・して・で","て・して・で"],"hot":true,"source":"03_古典文法_助詞.md","choices":["接続助詞「て・して・で」","形容動詞の活用","助動詞「なり」"]},{"id":"q31","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は反復・継続（〜しては・〜し続けて）と動作の並行を表します。【　　　】は並行（〜し【　　　】）と逆接（〜のままで・〜けれども）の意味を持ちます。」","answer":"接続助詞「つつ・ながら」","accept":["接続助詞「つつ・ながら」","接続助詞つつ・ながら","つつ・ながら"],"hot":false,"source":"03_古典文法_助詞.md","choices":["接続助詞「つつ・ながら」","助動詞「べし」","終助詞「な・そ・かな・は・よ」"]},{"id":"q32","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は類推（〜さえ）と最小限の限定（せめて〜だけでも）、【　　　】は類推（〜さえ）、【　　　】は添加（〜までも）を表します。【　　　】と【　　　】の意味の違い（限定・類推か、添加か）が識別問題で頻出です。」","answer":"副助詞「だに・すら・さへ」","accept":["副助詞「だに・すら・さへ」","副助詞だに・すら・さへ","だに・すら・さへ"],"hot":true,"source":"03_古典文法_助詞.md","choices":["副助詞「だに・すら・さへ」","助動詞「ごとし」","助動詞「なり・たり」"]},{"id":"q33","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は語調を整え強意を表す副助詞で、訳出しないことも多い語です。【　　　】は下に打消を伴うと部分否定（必ず【　　　】〜ない）になります。」","answer":"副助詞「し・しも」","accept":["副助詞「し・しも」","副助詞し・しも","し・しも"],"hot":false,"source":"03_古典文法_助詞.md","choices":["動詞の活用の種類","副助詞「し・しも」","助動詞「まほし・たし」"]},{"id":"q34","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「係助詞「ぞ・【　　　】・【　　　】」は強意、「や・か」は疑問・反語を表し、係り結びを起こします。「ぞ・【　　　】・や・か」は結びが連体形、【　　　】は已然形になります。」","answer":"係助詞「ぞ・なむ・や・か・こそ」","accept":["係助詞「ぞ・なむ・や・か・こそ」","係助詞ぞ・なむ・や・か・こそ","ぞ・なむ・や・か・こそ"],"hot":true,"source":"03_古典文法_助詞.md","choices":["「給ふ」の四段活用と下二段活用","係助詞「ぞ・なむ・や・か・こそ」","助動詞「たり・り」"]},{"id":"q35","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「は」は他と区別する取り立て、「も」は同類・添加・並列を表します。文の主題を示す基本的な係助詞で、係り結びは起こしません。」","answer":"係助詞「は・も」","accept":["係助詞「は・も」","係助詞は・も","は・も"],"hot":false,"source":"03_古典文法_助詞.md","choices":["係助詞「は・も」","変格活用","下一段活用"]},{"id":"q36","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「願望を表す終助詞には、他への願望【　　　】（〜してほしい・未然形接続）、自己の願望【　　　】（〜したい）、実現困難な願望【　　　】（〜があればなあ）、「【　　　】・にしがな」（〜したいものだ）があります。願望の対象の違いが頻出ポイントです。」","answer":"終助詞「なむ・ばや・もがな・てしがな」","accept":["終助詞「なむ・ばや・もがな・てしがな」","終助詞なむ・ばや・もがな・てしがな","なむ・ばや・もがな・てしがな"],"hot":true,"source":"03_古典文法_助詞.md","choices":["格助詞「が・の」","尊敬語の主な語","終助詞「なむ・ばや・もがな・てしがな」"]},{"id":"q37","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「な」は禁止（〜するな）、「な〜そ」は穏や【　　　】禁止（〜してくれるな）、「【　　　】・は・よ」は詠嘆（〜だなあ）を表します。特に「な〜そ」の呼応（副詞「な」と終助詞「そ」で挟む形）の識別が頻出です。」","answer":"終助詞「な・そ・かな・は・よ」","accept":["終助詞「な・そ・かな・は・よ」","終助詞な・そ・かな・は・よ","な・そ・かな・は・よ"],"hot":false,"source":"03_古典文法_助詞.md","choices":["終助詞「な・そ・かな・は・よ」","助動詞「なり・たり」","係助詞「ぞ・なむ・や・か・こそ」"]},{"id":"q38","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「係り結びとは、文中に係助詞があると文末（結び）の活用形が変化する法則です。「ぞ・なむ・や・か」があると結びは連体形、「こそ」があると結びは已然形になります。」","answer":"係り結びの法則","accept":["係り結びの法則"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["係り結びの法則","助動詞「ごとし」","助動詞「まし」"]},{"id":"q39","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「「ぞ・なむ・こそ」は強意（特に訳に表れない強調）、「や・か」は疑問（〜か）または反語（〜だろうか、いや〜ない）を表します。反語は文脈上「否定」の答えを導く点が重要で、疑問か反語かの判別が読解で頻出します。」","answer":"係り結びの意味","accept":["係り結びの意味"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["副助詞「し・しも」","助動詞「まし」","係り結びの意味"]},{"id":"q40","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「結びとなるはずの語の下にさらに語が続くと、係り結びが完成せず「結びの流れ（【　　　】）」が起こります。また「こそ〜已然形、」のように已然形で文が終わらず下に続くと逆接（〜けれども）の意味になります。」","answer":"係り結びの流れ・消滅","accept":["係り結びの流れ・消滅"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["敬語の種類","助動詞「す・さす・しむ」","係り結びの流れ・消滅"]},{"id":"q41","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「敬語には3種類あります。尊敬語は動作をする人を高める（給ふ・おはす等）、謙譲語は動作を受ける人を高める（奉る・申す等）、丁寧語は聞き手・読み手を高める（侍り・候ふ）です。」","answer":"敬語の種類","accept":["敬語の種類"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["形容動詞の活用","活用形","敬語の種類"]},{"id":"q42","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「主な尊敬語は「給ふ（四段）・おはす・おはします（いらっしゃる）・のたまふ（おっしゃる）・召す（お呼びになる・召し上がる）・大殿籠る（おやすみになる）・思す・おぼしめす（お思いになる）」です。動作主への敬意を表す点を押さえます。」","answer":"尊敬語の主な語","accept":["尊敬語の主な語"],"hot":false,"source":"04_古典文法_係り結びと敬語.md","choices":["謙譲語の主な語","尊敬語の主な語","助動詞「なり・たり」"]},{"id":"q43","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「主な謙譲語は「奉る・参らす（差し上げる）・申す・聞こゆ（申し上げる）・参る・まうづ（参上する）・まかる・まかづ（退出する）・賜はる（いただく）・侍り（お仕えする）」です。動作の受け手への敬意を表します。」","answer":"謙譲語の主な語","accept":["謙譲語の主な語"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["終助詞「なむ・ばや・もがな・てしがな」","四段活用","謙譲語の主な語"]},{"id":"q44","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「主な丁寧語は「侍り・候ふ（さぶらふ／さうらふ）」で、「〜です・〜ます・〜ございます」と訳します。会話文や手紙文で聞き手への敬意を表すのが基本で、「あり・をり」の丁寧語としても用いられます。」","answer":"丁寧語の主な語","accept":["丁寧語の主な語"],"hot":false,"source":"04_古典文法_係り結びと敬語.md","choices":["格助詞「が・の」","絶対敬語","丁寧語の主な語"]},{"id":"q45","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】には四段活用（尊敬語：お〜になる）と下二段活用（謙譲語：〜ております）の二つがあります。下二段の【　　　】は「思ふ・見る・聞く・知る」など知覚動詞に付き会話文で用いられる点が特徴で、識別が頻出です。」","answer":"「給ふ」の四段活用と下二段活用","accept":["「給ふ」の四段活用と下二段活用","給ふの四段活用と下二段活用","給ふ"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["敬語の種類","「給ふ」の四段活用と下二段活用","助動詞「き・けり」"]},{"id":"q46","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は尊敬語を重ねて最高位の人物への敬意を表す表現です。「せ給ふ・させ給ふ・しめ給ふ」「のたまはす」などが代表例で、天皇・皇后・上皇など最高位の人物に用いられます。」","answer":"二重敬語","accept":["二重敬語"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["「給ふ」の四段活用と下二段活用","二重敬語","助動詞「ごとし」"]},{"id":"q47","theme":"古典文法","question":"次の説明が指すものを答えなさい。\n「【　　　】は特定の最高位の人物にのみ用いられる敬語です。「奏す」は天皇・上皇に申し上げる、「啓す」は皇后・皇太子・中宮に申し上げる意味です。」","answer":"絶対敬語","accept":["絶対敬語"],"hot":true,"source":"04_古典文法_係り結びと敬語.md","choices":["絶対敬語","「給ふ」の四段活用と下二段活用","四段活用"]},{"id":"q48","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】はしみじみとした情趣を表す語で、「しみじみと心打たれる・趣深い・かわいそうだ」と訳します。喜怒哀楽すべての深い感動に用いられ、平安文学（特に『源氏物語』）の美的理念を示す重要語です。」","answer":"あはれなり","accept":["あはれなり"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["あはれなり","はかなし","つきづきし"]},{"id":"q49","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は明るく知的な美を表す語で、「趣がある・風情がある・興味深い・こっけいだ」と訳します。『枕草子』を代表する美意識で、「あはれ」が情緒的なのに対し【　　　】は理知的・客観的な美を示す点が対比で頻出します。」","answer":"をかし","accept":["をかし"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["かたはらいたし","ゆゆし","をかし"]},{"id":"q50","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「かわいい・いとしい」という意味で、小さいものや幼いものへの愛情を表します。現代語の「美しい」とは異なり、容姿の美ではなく愛らしさを表す点が頻出の注意語です。」","answer":"うつくし","accept":["うつくし"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["おどろく","うつくし","なつかし"]},{"id":"q51","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「めったにない・珍しい・難しい」という意味です。「有り難し」＝存在しがたい、が原義で、現代語の「感謝」の意味はありません。」","answer":"ありがたし","accept":["ありがたし"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["ありがたし","つきづきし","まめなり"]},{"id":"q52","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「恥ずかしい・きまりが悪い・つらい」、さらに「優美だ・けなげだ」の意味を持ちます。「身もやせるほどつらい」が原義で、現代語の「優しい（親切）」とは異なる点が要注意です。」","answer":"やさし","accept":["やさし"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["やさし","うし","はかなし"]},{"id":"q53","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「つらい・いやだ・憂鬱だ」という意味で、自分の身の上を嘆く心情を表します。「つらし」が他者に対する非難を含むのに対し、【　　　】は自分の内側に向かう嘆きである点が読解で重要です。」","answer":"うし","accept":["うし"],"hot":false,"source":"05_古文単語_頻出語.md","choices":["おぼつかなし","なつかし","うし"]},{"id":"q54","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は程度のはなはだしさを表す語で、文脈により「ひどく良い・すばらしい」とも「ひどく悪い・恐ろしい」とも訳します。良い意味か悪い意味かを文脈で判断する必要がある点が頻出です。」","answer":"いみじ","accept":["いみじ"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["かたはらいたし","いみじ","あそぶ"]},{"id":"q55","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「不吉だ・恐れ多い」が原義で、転じて「はなはだしい・すばらしい」の意味にもなります。神聖なものに触れてはならないという畏怖の感情が根底にあり、良悪両方の程度の強さを表します。」","answer":"ゆゆし","accept":["ゆゆし"],"hot":false,"source":"05_古文単語_頻出語.md","choices":["ゆゆし","ののしる","なつかし"]},{"id":"q56","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「まじめだ・誠実だ・実用的だ」という意味です。「まめまめし」も同様に誠実・実直を表します。」","answer":"まめなり","accept":["まめなり"],"hot":false,"source":"05_古文単語_頻出語.md","choices":["まめなり","おどろく","ときめく"]},{"id":"q57","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「似つかわしい・ふさわしい・調和している」という意味です。『枕草子』の「冬はつとめて」の段で雪や霜と火桶の調和を述べる場面が有名で、調和・適合を表す美的語として頻出します。」","answer":"つきづきし","accept":["つきづきし"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["つきづきし","ののしる","さうざうし"]},{"id":"q58","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「はっと気づく・目を覚ます」という意味が中心です。現代語の「驚く（びっくりする）」の意味もありますが、「目が覚める・ふと気づく」の意で問われることが多い注意語です。」","answer":"おどろく","accept":["おどろく"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["おどろく","をかし","ときめく"]},{"id":"q59","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「大声で騒ぐ・評判になる」という意味です。現代語の「罵る（悪口を言う）」とは異なり、大声を立てて騒ぐ・世間で評判が高いの意で用いられる点が頻出の注意語です。」","answer":"ののしる","accept":["ののしる"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["ののしる","なつかし","うつくし"]},{"id":"q60","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「いとしい・かわいい」と「悲しい・切ない」の両義を持ちます。「愛し」と書けば肉親や恋人への深い愛情を、「悲し」と書けば悲哀を表します。」","answer":"かなし","accept":["かなし"],"hot":false,"source":"05_古文単語_頻出語.md","choices":["うつくし","かなし","ありがたし"]},{"id":"q61","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「ほんの少し・かりそめだ・ちょっと」という意味で、短時間・一時的なさまを表します。現代語の「あからさま（露骨）」とは全く異なる意味であり、誤訳しやすい頻出語です。」","answer":"あからさまなり","accept":["あからさまなり"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["あからさまなり","おとなし","いたづらなり"]},{"id":"q62","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「そのまま・すぐに」という意味です。現代語の「【　　　】（しばらくして）」のような時間的隔たりはなく、「そのまま即座に」の意で用いられる点が時間表現の注意語として頻出します。」","answer":"やがて","accept":["やがて"],"hot":true,"source":"05_古文単語_頻出語.md","choices":["ゆゆし","やがて","いみじ"]},{"id":"q63","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「自然に思われる・思い出される・似る」の多義語です。「思ふ」が意図的なのに対し【　　　】は自然にそう感じられる自発の意を含みます。」","answer":"おぼゆ","accept":["おぼゆ"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["あはれなり","ゆゆし","おぼゆ"]},{"id":"q64","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「寵愛を受ける・時流に乗って栄える」という意味です。現代語の「胸が【　　　】」とは異なり、帝などの権力者から特別な寵愛を受けて栄える意で用いられます。」","answer":"ときめく","accept":["ときめく"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["うつくし","かなし","ときめく"]},{"id":"q65","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「詩歌・管弦を楽しむ」という意味が中心です。単なる遊戯ではなく、和歌を詠んだり楽器を演奏したりする風雅な遊びを指します。」","answer":"あそぶ","accept":["あそぶ"],"hot":false,"source":"06_古文単語_多義語と注意語.md","choices":["さうざうし","あそぶ","ふみ"]},{"id":"q66","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「心が引かれる・親しみが持てる・慕わしい」という意味です。現代語の「過去を懐かしむ」の意味は薄く、対象に心が引きつけられる愛着の感情を表す点が注意語として頻出します。」","answer":"なつかし","accept":["なつかし"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["なつかし","やがて","さうざうし"]},{"id":"q67","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「待ち遠しい・じれったい・気がかりだ・不安だ」という意味です。待ち望むあまり落ち着かない心情を表し、現代語にはない「待ち遠しさ・じれったさ」のニュアンスが頻出ポイントです。」","answer":"こころもとなし","accept":["こころもとなし"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["おぼゆ","こころもとなし","やがて"]},{"id":"q68","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「みっともない・気の毒だ・恥ずかしい」という意味です。傍で見ていて心が痛む、の意で、自分にも他人にも用います。」","answer":"かたはらいたし","accept":["かたはらいたし"],"hot":false,"source":"06_古文単語_多義語と注意語.md","choices":["いみじ","かたはらいたし","おどろく"]},{"id":"q69","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「むなしい・無駄だ・手持ちぶさただ」という意味です。現代語の「いたずら（悪ふざけ）」とは無関係で、何の役にも立たない・空虚であるさまを表す点が誤訳しやすい頻出語です。」","answer":"いたづらなり","accept":["いたづらなり"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["いたづらなり","ののしる","やさし"]},{"id":"q70","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「大人びている・分別がある・年配だ」という意味です。現代語の「【　　　】い（静かで従順）」ではなく、年長で思慮分別があるさまを表します。」","answer":"おとなし","accept":["おとなし"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["こころもとなし","おとなし","さうざうし"]},{"id":"q71","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「もの足りない・心寂しい」という意味です。あるべきものがなくて物足りない感じを表し、現代語の「騒々しい」とは全く異なります。」","answer":"さうざうし","accept":["さうざうし"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["さうざうし","おどろく","ゆゆし"]},{"id":"q72","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「どうしようもない・つまらない・道理に合わない」という意味です。思い通りにならず嫌気がさすさまを表し、無常観や諦めの心情を伴って用いられることが多い語です。」","answer":"あぢきなし","accept":["あぢきなし"],"hot":false,"source":"06_古文単語_多義語と注意語.md","choices":["こころもとなし","なつかし","あぢきなし"]},{"id":"q73","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「手紙・訪問・取り次ぎを頼むこと」という意味です。現代語の「消息（安否）」よりも広く、便りや訪問、案内を請うことなど人と人との連絡全般を指す点が頻出です。」","answer":"せうそこ","accept":["せうそこ"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["こころもとなし","ゆゆし","せうそこ"]},{"id":"q74","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「居る（座る・とまる・存在する）」と「率る（引き連れる）」の二語があります。「率る」は「ゐて行く（連れて行く）・ゐて来（連れて来る）」の形で頻出し、動作の主従関係を読む鍵になります。」","answer":"ゐる","accept":["ゐる"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["やさし","ゐる","うつくし"]},{"id":"q75","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「あっけない・頼りない・むなしい・ちょっとした」という意味です。長続きせずもろいさまを表し、無常観と結びつく語です。」","answer":"はかなし","accept":["はかなし"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["ふみ","おとなし","はかなし"]},{"id":"q76","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「ぼんやりしている・気がかりだ・待ち遠しい」という意味です。はっきりせず不安に思う心情を表し、「こころもとなし」と近い意味で用いられます。」","answer":"おぼつかなし","accept":["おぼつかなし"],"hot":false,"source":"06_古文単語_多義語と注意語.md","choices":["まめなり","おぼつかなし","やさし"]},{"id":"q77","theme":"古文単語","question":"次の説明が指すものを答えなさい。\n「【　　　】は「手紙・漢詩文・学問・書物」という意味の多義語です。文脈により「恋文」を指したり「漢学・学問」を指したりします。」","answer":"ふみ","accept":["ふみ"],"hot":true,"source":"06_古文単語_多義語と注意語.md","choices":["いたづらなり","ふみ","なつかし"]},{"id":"q78","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「上代は奈良時代を中心とする時期で、文字（漢字）による記録が始まりました。歴史書『古事記』『日本書紀』、地誌『風土記』、現存最古の歌集『万葉集』、漢詩集『懐風藻』が成立しました。」","answer":"上代の文学","accept":["上代の文学"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["伊勢物語","上代の文学","新古今和歌集"]},{"id":"q79","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「中古は平安時代で、仮名文字の発達により女性による仮名文学が花開きました。物語・日記・随筆・歌物語が栄え、『源氏物語』『枕草子』『古今和歌集』など王朝文学の最高峰が生まれました。」","answer":"中古の文学","accept":["中古の文学"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["源氏物語","中古の文学","随筆"]},{"id":"q80","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「中世は鎌倉・室町時代で、武士の台頭と戦乱を背景に無常観が文学の基調となりました。軍記物語『平家物語』、随筆『方丈記』『徒然草』、和歌集『新古今和歌集』、能・狂言・連歌が発達しました。」","answer":"中世の文学","accept":["中世の文学"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["中世の文学","説話文学","勅撰和歌集"]},{"id":"q81","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「近世は江戸時代で、町人文化の発展により庶民的な文学が広まりました。浮世草子（井原西鶴）、俳諧（松尾芭蕉）、人形浄瑠璃・歌舞伎（近松門左衛門）、読本（上田秋成・滝沢馬琴）が栄えました。」","answer":"近世の文学","accept":["近世の文学"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["竹取物語","近世の文学","大鏡"]},{"id":"q82","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は内容により分類されます。作り【　　　】（虚構：竹取【　　　】・源氏【　　　】）、歌【　　　】（和歌中心：伊勢【　　　】・大和【　　　】）、歴史【　　　】（史実を【　　　】化：大鏡・栄花【　　　】）、軍記【　　　】（合戦記：平家【　　　】・太平記）に分かれます。」","answer":"物語","accept":["物語"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["方丈記","物語","竹取物語"]},{"id":"q83","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は自己の体験や心情を仮名で綴る文学で、平安時代に女性によって発達しました。『土佐日記』（紀貫之・男性が女性に仮託）、『蜻蛉日記』『和泉式部日記』『紫式部日記』『更級日記』が代表作です。」","answer":"日記文学","accept":["日記文学"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["伊勢物語","近世の文学","日記文学"]},{"id":"q84","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は見聞や感想を自由に書き綴る散文で、「三大【　　　】」が頻出です。平安の『枕草子』（清少納言）、鎌倉の『方丈記』（鴨長明）、鎌倉末〜南北朝の『徒然草』（兼好法師）を三大【　　　】と呼びます。」","answer":"随筆","accept":["随筆"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["随筆","説話文学","上代の文学"]},{"id":"q85","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は民間に伝わる説話を集めた文学です。仏教説話と世俗説話があり、『今昔物語集』（最大の説話集）、『宇治拾遺物語』『十訓抄』『古今著聞集』『発心集』などが代表作です。」","answer":"説話文学","accept":["説話文学"],"hot":false,"source":"07_文学史_時代区分とジャンル.md","choices":["日記文学","物語","説話文学"]},{"id":"q86","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は天皇・上皇の命で編まれた和歌集です。最初の八集を「八代集」と呼び、『古今和歌集』に始まり『新古今和歌集』に至ります。」","answer":"勅撰和歌集","accept":["勅撰和歌集"],"hot":true,"source":"07_文学史_時代区分とジャンル.md","choices":["随筆","勅撰和歌集","中世の文学"]},{"id":"q87","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は和歌の上の句と下の句を複数人で詠み継ぐ文芸で、室町時代に大成しました。そこから滑稽味を加えた【　　　】が生まれ、江戸時代に松尾芭蕉が芸術性を高めた「蕉風【　　　】」を確立しました。」","answer":"俳諧・連歌","accept":["俳諧・連歌"],"hot":false,"source":"07_文学史_時代区分とジャンル.md","choices":["方丈記","源氏物語","俳諧・連歌"]},{"id":"q88","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安初期に成立した、現存最古の作り物語です。作者未詳で、かぐや姫の昇天を描きます。」","answer":"竹取物語","accept":["竹取物語"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["勅撰和歌集","竹取物語","俳諧・連歌"]},{"id":"q89","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安初期成立の歌物語で、作者未詳です。在原業平とおぼしき「昔男」の一代記を、和歌を中心に約125段で構成します。」","answer":"伊勢物語","accept":["伊勢物語"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["竹取物語","大鏡","伊勢物語"]},{"id":"q90","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安中期、紫式部によって書かれた全54帖の長編物語です。光源氏とその子孫を主人公に、宮廷貴族の恋愛と人生を描きます。」","answer":"源氏物語","accept":["源氏物語"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["おくのほそ道","源氏物語","随筆"]},{"id":"q91","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安中期、清少納言による随筆で、日本最初の随筆とされます。一条天皇の中宮定子に仕えた作者の観察と感想を、「ものづくし（類聚的章段）」「日記的章段」「随想的章段」で綴ります。」","answer":"枕草子","accept":["枕草子"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["中古の文学","徒然草","枕草子"]},{"id":"q92","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安前期、醍醐天皇の命で紀貫之らが編纂した最初の勅撰和歌集です。仮名序（紀貫之）と真名序を持ち、七五調・三句切れ・縁語・掛詞を駆使した理知的・技巧的歌風が特徴です。」","answer":"古今和歌集","accept":["古今和歌集"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["古今和歌集","方丈記","伊勢物語"]},{"id":"q93","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安前期、紀貫之による日記文学で、最初の仮名日記です。土佐から京へ帰る旅を、作者が女性に仮託して仮名で記しました。」","answer":"土佐日記","accept":["土佐日記"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["物語","中古の文学","土佐日記"]},{"id":"q94","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安後期成立の歴史物語で、作者未詳です。藤原道長の栄華を中心に、大宅世継・夏山繁樹という二人の老人の対話形式（紀伝体）で歴史を語ります。」","answer":"大鏡","accept":["大鏡"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["随筆","枕草子","大鏡"]},{"id":"q95","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は鎌倉前期、鴨長明による随筆で三大随筆の一つです。「ゆく河の流れは絶えずして…」の冒頭で無常観を表明し、大火・竜巻・飢饉などの天変地異を記録した後、自身の隠遁生活を描きます。」","answer":"方丈記","accept":["方丈記"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["勅撰和歌集","方丈記","枕草子"]},{"id":"q96","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は鎌倉末期、兼好法師（吉田兼好）による随筆で三大随筆の一つです。「つれづれなるままに…」の序段で始まり、無常観・処世訓・有職故実・美意識など多彩な内容を約240段で綴ります。」","answer":"徒然草","accept":["徒然草"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["伊勢物語","徒然草","近世の文学"]},{"id":"q97","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は鎌倉時代成立の軍記物語で、作者は信濃前司行長とも伝わります。「祇園精舎の鐘の声、諸行無常の響きあり」で始まり、平家の栄華と滅亡を仏教的無常観で描きます。」","answer":"平家物語","accept":["平家物語"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["源氏物語","平家物語","おくのほそ道"]},{"id":"q98","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は鎌倉前期、後鳥羽院の命で藤原定家らが編纂した八代集最後の勅撰集です。本歌取り・体言止め・初句切れ・三句切れ・幽玄・余情を特徴とし、技巧的で象徴的な歌風を確立しました。」","answer":"新古今和歌集","accept":["新古今和歌集"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["新古今和歌集","説話文学","日記文学"]},{"id":"q99","theme":"文学史","question":"次の説明が指すものを答えなさい。\n「【　　　】は江戸前期、松尾芭蕉による俳諧紀行文です。元禄2年、江戸から東北・北陸をめぐり大垣に至る旅を、俳句を交えた格調高い文章で記しました。」","answer":"おくのほそ道","accept":["おくのほそ道"],"hot":true,"source":"08_文学史_代表作品と作者.md","choices":["おくのほそ道","上代の文学","日記文学"]},{"id":"q100","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「和歌（短歌）は「五・七・五・七・七」の三十一音から成り、上から初句・二句・三句・四句・結句と呼びます。意味や調子の切れ目を「句切れ」といい、初句切れ・二句切れ・三句切れなどがあります。」","answer":"五七五七七と句切れ","accept":["五七五七七と句切れ"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["序詞","五七五七七と句切れ","倒置法・対句"]},{"id":"q101","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は特定の語を導く、原則五音の修飾語で、それ自体は訳しません。「ちはやぶる→神」「あしひきの→山」「ひさかたの→光・天」「たらちねの→母」「あをによし→奈良」などが代表例です。」","answer":"枕詞","accept":["枕詞"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["枕詞","紀貫之","序詞"]},{"id":"q102","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】はある語句を導き出すために置かれる、七音以上の比較的長い修飾表現です。枕詞と違い字数や導く語が一定でなく、その都度作者が創作します。」","answer":"序詞","accept":["序詞"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["垣間見","序詞","賀茂祭と斎院・斎宮"]},{"id":"q103","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は同音を利用して一語に二つの意味を持たせる技法です。「まつ（松・待つ）」「あき（秋・飽き）」「ながめ（長雨・眺め）」「よ（夜・世）」「うき（憂き・浮き）」などが頻出で、自然と心情の二重の意味を重ねます。」","answer":"掛詞","accept":["掛詞"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["立ち別れいなばの山の","屏風歌・歌合の文化","掛詞"]},{"id":"q104","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は一首の中に意味上関連する語を意図的に散りばめ、連想で歌に深みを与える技法です。例えば「糸」に対し「張る・乱る・よる・絶ゆ」、「波」に対し「立つ・寄る・返る」を配します。」","answer":"縁語","accept":["縁語"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["縁語","花さそふ嵐の庭の","旅と望郷の歌"]},{"id":"q105","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は有名な古歌（本歌）の語句や趣向を意図的に取り入れ、新たな歌を詠む技法です。元の歌を背景に重層的な余情を生み出します。」","answer":"本歌取り","accept":["本歌取り"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["縁語","本歌取り","物忌みと方違え"]},{"id":"q106","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は結句を名詞（体言）で終える技法で、余情・余韻を残す効果があります。『新古今和歌集』に多く見られ、言い切らないことで読者の想像を誘います。」","answer":"体言止め","accept":["体言止め"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["花さそふ嵐の庭の","体言止め","序詞"]},{"id":"q107","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は語順を入れ替えて強調や余情を生む技法、【　　　】は対応する語句を並べて調子を整える技法です。和歌の表現効果を問う設問で扱われることがあり、強調・印象づけの働きを理解しておくことが大切です。」","answer":"倒置法・対句","accept":["倒置法・対句"],"hot":false,"source":"09_和歌_技法と修辞法.md","choices":["倒置法・対句","垣間見","旧暦と季節のずれ"]},{"id":"q108","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は各句の頭に語を一字ずつ詠み込む技法で、『伊勢物語』東下りの「かきつばた」を詠み込んだ歌が有名です。【　　　】（隠し題）は歌の意味とは別に物の名を句中に隠す言葉遊びです。」","answer":"折句・物名","accept":["折句・物名"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["三大歌集の比較","枕詞","折句・物名"]},{"id":"q109","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は和歌に詠み込まれる名所・地名で、特定のイメージや連想を伴います。「龍田川→紅葉」「吉野→桜・雪」「逢坂の関→逢う」「天の橋立」などが代表例です。」","answer":"歌枕","accept":["歌枕"],"hot":true,"source":"09_和歌_技法と修辞法.md","choices":["夢と魂・恋の俗信","歌枕","後鳥羽院"]},{"id":"q110","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「在原業平の「【　　　】からくれなゐに水くくるとは」は、竜田川の紅葉の美を詠んだ歌です。「ちはやぶる」は「神」を導く枕詞で、神代でも聞いたことがないほど紅葉が川を真紅に染める様子を誇張的に讃えています。」","answer":"ちはやぶる神代も聞かず竜田川","accept":["ちはやぶる神代も聞かず竜田川"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["在原業平","ちはやぶる神代も聞かず竜田川","式子内親王の忍ぶ恋"]},{"id":"q111","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「山部赤人の「【　　　】白妙の富士の高嶺に雪は降りつつ」は、富士の雪景色を詠んだ叙景歌です。「白妙の」は「雪」を導く枕詞で、清新で雄大な自然描写が万葉調の特徴を示します。」","answer":"田子の浦にうち出でて見れば","accept":["田子の浦にうち出でて見れば"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["倒置法・対句","田子の浦にうち出でて見れば","月の異名"]},{"id":"q112","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「柿本人麻呂の「【　　　】しだり尾の長々し夜をひとりかも寝む」は、独り寝のわびしさを詠んだ歌です。「【　　　】しだり尾の」までが「長々し」を導く序詞で、長い夜の孤独を山鳥の長い尾に重ねています。」","answer":"あしびきの山鳥の尾の","accept":["あしびきの山鳥の尾の"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["あしびきの山鳥の尾の","物忌みと方違え","体言止め"]},{"id":"q113","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「小野小町の「【　　　】いたづらにわが身世にふるながめせしまに」は、女性の容姿の衰えを花に重ねた歌です。「ふる（経る・降る）」「ながめ（眺め・長雨）」が掛詞で、桜の色あせと我が身の老いを二重に詠む技巧が頻出です。」","answer":"花の色は移りにけりな","accept":["花の色は移りにけりな"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["花さそふ嵐の庭の","花の色は移りにけりな","柿本人麻呂"]},{"id":"q114","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「「【　　　】雪ならでふりゆくものはわが身なりけり」は、散る桜を雪に見立て、老いゆく身を嘆く歌です。「ふり（降り・古り）」が掛詞で、散る花びらと自分が年老いていくことを重ねています。」","answer":"花さそふ嵐の庭の","accept":["花さそふ嵐の庭の"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["花さそふ嵐の庭の","序詞","垣間見"]},{"id":"q115","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「在原行平の「【　　　】峰に生ふるまつとし聞かば今帰り来む」は、別れの際の再会を願う歌です。「いなば（往なば・因幡）」「まつ（松・待つ）」が掛詞で、地名と心情を巧みに重ねた掛詞の代表例として頻出します。」","answer":"立ち別れいなばの山の","accept":["立ち別れいなばの山の"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["賀茂祭と斎院・斎宮","立ち別れいなばの山の","後鳥羽院"]},{"id":"q116","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「『古今和歌集』の歌風は、掛詞・縁語を駆使した理知的・技巧的なものです。七五調・三句切れが多く、優美で繊細な「たをやめぶり」と評されます。」","answer":"古今和歌集の歌風","accept":["古今和歌集の歌風"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["古今和歌集の歌風","屏風歌・歌合の文化","縁語"]},{"id":"q117","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「『新古今和歌集』の歌風は、本歌取り・体言止め・初句切れ・三句切れを特徴とし、幽玄・余情を重んじる象徴的・絵画的なものです。藤原定家・西行・式子内親王らが代表歌人で、技巧の頂点とされる点が頻出です。」","answer":"新古今和歌集の歌風","accept":["新古今和歌集の歌風"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["六歌仙","夢と魂・恋の俗信","新古今和歌集の歌風"]},{"id":"q118","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「『万葉集』の歌風は、素朴で力強く率直な「ますらをぶり」と評されます。五七調・二句切れ・四句切れが多く、額田王・柿本人麻呂・山上憶良・大伴家持らが代表歌人です。」","answer":"万葉集の歌風","accept":["万葉集の歌風"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["花の色は移りにけりな","折句・物名","万葉集の歌風"]},{"id":"q119","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「万葉・古今・新古今を「三大歌集」と呼びます。万葉＝ますらをぶり・五七調・素朴、古今＝たをやめぶり・七五調・技巧、新古今＝幽玄余情・本歌取り・体言止め、と各集の歌風と特徴語を対比して覚えるのが頻出の整理ポイントです。」","answer":"三大歌集の比較","accept":["三大歌集の比較"],"hot":true,"source":"10_和歌_百人一首と勅撰集.md","choices":["贈答歌の読解","三大歌集の比較","月・露・夢が表す心情"]},{"id":"q120","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「和歌読解はまず句切れと修辞（掛詞・序詞）を見抜き、次に詠み手の置かれた状況と心情を文脈から読み取ります。地の文（詞書）に詠歌の事情が書かれることが多く、詞書と和歌を結びつけて解釈するのが鉄則です。」","answer":"和歌の内容読解の基本手順","accept":["和歌の内容読解の基本手順"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["和歌の内容読解の基本手順","西行","六歌仙"]},{"id":"q121","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「贈答歌は男女や友人間でやり取りされる歌で、相手の歌の語句を受けて返す「返歌」の技法が重要です。返歌では相手の歌の語句・趣向を踏まえて応じるのが約束で、二首の関係を読み解く問題が頻出します。」","answer":"贈答歌の読解","accept":["贈答歌の読解"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["縁語","贈答歌の読解","物忌みと方違え"]},{"id":"q122","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「和歌では「袖」が涙でぬれるものとして頻出します。「袖の涙」「袖をしぼる」「袖の露」は深い悲しみや恋の苦しみを表す決まり文句です。」","answer":"袖と涙の連想","accept":["袖と涙の連想"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["袖と涙の連想","時代背景 ― 平安貴族の恋愛","贈答歌の読解"]},{"id":"q123","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「月は孤独・物思い・遠い人への思慕、露は，はかなさ・涙・短命、夢は恋しい人との逢瀬や現実のはかなさを象徴します。これらの景物が表す定型的な心情を知ることで、叙景の奥にある心情を読み取れます。」","answer":"月・露・夢が表す心情","accept":["月・露・夢が表す心情"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["月・露・夢が表す心情","新古今和歌集の歌風","西行の歌と無常観"]},{"id":"q124","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「恋の歌では「【　　　】（秋・飽き）」の掛詞が頻出します。秋の訪れに男の心変わり（飽き）を重ね、恋の終わりや嘆きを表現します。」","answer":"「あき」の掛詞と恋の歌","accept":["「あき」の掛詞と恋の歌","あきの掛詞と恋の歌","あき"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["月の異名","「あき」の掛詞と恋の歌","藤原定家"]},{"id":"q125","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「旅の歌では故郷や都への思慕（望郷）が主題となります。『伊勢物語』東下りの「唐衣きつつなれにしつましあればはるばる来ぬる旅をしぞ思ふ」は、「かきつばた」の折句と「つま（妻・褄）」「はるばる（張る・遥々）」の掛詞で望郷を詠む頻出歌です。」","answer":"旅と望郷の歌","accept":["旅と望郷の歌"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["旅と望郷の歌","服喪と喪服の色","三十六歌仙"]},{"id":"q126","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「西行の「願はくは花の下にて春死なむそのきさらぎの望月のころ」は、桜の下での往生を願う歌です。出家して諸国を旅した西行は、花（桜）と月を愛し無常観を詠みました。」","answer":"西行の歌と無常観","accept":["西行の歌と無常観"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["贈答歌の読解","夢と魂・恋の俗信","西行の歌と無常観"]},{"id":"q127","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「式子内親王の「玉の緒よ絶えなば絶えねながらへば忍ぶることの弱りもぞする」は、秘めた恋の激情を詠んだ歌です。「玉の緒（命）」が絶えるなら絶えてしまえ、生き永らえれば恋を隠す力が弱ってしまう、という切実な心情が頻出します。」","answer":"式子内親王の忍ぶ恋","accept":["式子内親王の忍ぶ恋"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["式子内親王の忍ぶ恋","時代背景 ― 出家と隠遁","本歌取り"]},{"id":"q128","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「平安貴族の恋愛は、男が女のもとに通う「通い婚」が基本でした。男はまず和歌を贈り、女が返歌で応じることで関係が進みます。」","answer":"時代背景 ― 平安貴族の恋愛","accept":["時代背景―平安貴族の恋愛"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["折句・物名","時代背景 ― 平安貴族の恋愛","垣間見"]},{"id":"q129","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「中世には世の無常を感じて出家・隠遁する人が多く、和歌にも無常観が色濃く反映されました。西行・鴨長明・兼好らの隠者文学が代表で、俗世を離れた境地から自然や人生を見つめる視点が和歌・随筆に共通する点が頻出です。」","answer":"時代背景 ― 出家と隠遁","accept":["時代背景―出家と隠遁"],"hot":true,"source":"11_和歌_入試頻出歌と読解.md","choices":["月・露・夢が表す心情","時代背景 ― 出家と隠遁","通い婚"]},{"id":"q130","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「平安期には屏風絵に添える【　　　】や、左右に分かれて歌の優劣を競う「歌合」が盛んでした。題に応じて詠む「題詠」が発達し、技巧的な歌が生まれました。」","answer":"屏風歌・歌合の文化","accept":["屏風歌・歌合の文化"],"hot":false,"source":"11_和歌_入試頻出歌と読解.md","choices":["屏風歌・歌合の文化","服喪と喪服の色","後朝の文"]},{"id":"q131","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『万葉集』を代表する宮廷歌人で、「歌聖」と称されます。長歌に優れ、荘重で格調高い枕詞・序詞を駆使した雄大な歌風が特徴です。」","answer":"柿本人麻呂","accept":["柿本人麻呂"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["三大歌集の比較","柿本人麻呂","三十六歌仙"]},{"id":"q132","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『万葉集』の歌人で、社会的・人間的な主題を詠んだ点が特徴です。「貧窮問答歌」で貧しい民の苦しみを、「子等を思ふ歌」で子への愛を詠みました。」","answer":"山上憶良","accept":["山上憶良"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["山上憶良","在原業平","万葉集の歌風"]},{"id":"q133","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『古今和歌集』の撰者の中心で、仮名序を執筆しました。理知的・技巧的な古今調を代表し、『土佐日記』の作者でもあります。」","answer":"紀貫之","accept":["紀貫之"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["紀貫之","贈答歌の読解","旧暦と季節のずれ"]},{"id":"q134","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は六歌仙・三十六歌仙の一人で、『古今和歌集』を代表する女性歌人です。夢・恋・容姿の衰えを情熱的かつ繊細に詠み、絶世の美女としても伝説化されました。」","answer":"小野小町","accept":["小野小町"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["花の色は移りにけりな","小野小町","袖と涙の連想"]},{"id":"q135","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は六歌仙の一人で、『伊勢物語』の主人公「昔男」のモデルとされます。情熱的で奔放な恋の歌を詠み、技巧よりも心情の率直さを重んじた歌風が特徴です。」","answer":"在原業平","accept":["在原業平"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["七夕・重陽などの節句","夢と魂・恋の俗信","在原業平"]},{"id":"q136","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『古今和歌集』仮名序で紀貫之が論評した六人の歌人です。在原業平・小野小町・僧正遍昭・喜撰法師・文屋康秀・大友黒主を指します。」","answer":"六歌仙","accept":["六歌仙"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["六歌仙","万葉集の歌風","五七五七七と句切れ"]},{"id":"q137","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安末〜鎌倉初期の歌人で、武士の身分を捨てて出家し諸国を旅しました。桜と月を愛し、無常観と自然への深い感動を平明に詠みました。」","answer":"西行","accept":["西行"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["出家と「世を捨つ」","式子内親王","西行"]},{"id":"q138","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『新古今和歌集』の撰者の一人で、『小倉百人一首』の撰者でもあります。本歌取りや幽玄・有心を理論化し、技巧的で象徴的な新古今調を主導しました。」","answer":"藤原定家","accept":["藤原定家"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["万葉集の歌風","藤原定家","「あき」の掛詞と恋の歌"]},{"id":"q139","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『新古今和歌集』を代表する女性歌人で、後白河天皇の皇女です。賀茂斎院を務めた経歴を持ち、秘めた恋（忍ぶ恋）や孤独を繊細かつ激情的に詠みました。」","answer":"式子内親王","accept":["式子内親王"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["垣間見","式子内親王","ちはやぶる神代も聞かず竜田川"]},{"id":"q140","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は『新古今和歌集』の編纂を命じた上皇で、自らも優れた歌人でした。和歌所を設置して歌壇を主導し、承久の乱で隠岐に流されました。」","answer":"後鳥羽院","accept":["後鳥羽院"],"hot":true,"source":"12_和歌_歌人と歌風.md","choices":["倒置法・対句","田子の浦にうち出でて見れば","後鳥羽院"]},{"id":"q141","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「【　　　】は、藤原公任が『三十六人撰』で選んだ和歌の名人三十六人です。柿本人麻呂・紀貫之・在原業平・小野小町・伊勢・大伴家持らが含まれます。」","answer":"三十六歌仙","accept":["三十六歌仙"],"hot":false,"source":"12_和歌_歌人と歌風.md","choices":["在原業平","三十六歌仙","物忌みと方違え"]},{"id":"q142","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『源氏物語』は全54帖で、紫式部が平安中期に著しました。光源氏の誕生から栄華を描く第一部、源氏の苦悩と紫の上の死までの第二部、源氏死後の薫・匂宮を描く第三部（宇治十帖）の三部構成とされます。」","answer":"源氏物語の構成","accept":["源氏物語の構成"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["徒然草の無常観と美意識","六条御息所と物の怪","源氏物語の構成"]},{"id":"q143","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は物語の主人公で、桐壺帝の第二皇子です。容姿・才能ともに優れ「光る君」と呼ばれますが、臣下に降下します。」","answer":"光源氏","accept":["光源氏"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["方丈記の無常観","土佐日記の内容","光源氏"]},{"id":"q144","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「「桐壺」の巻は物語の発端で、光源氏の母・桐壺更衣を描きます。帝の寵愛を一身に受けた更衣は、他の妃たちの嫉妬の中で源氏を産み、まもなく病死します。」","answer":"桐壺の巻と桐壺更衣","accept":["桐壺の巻と桐壺更衣"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["「春はあけぼの」の段","宇治十帖","桐壺の巻と桐壺更衣"]},{"id":"q145","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は桐壺帝の后で、亡き桐壺更衣に生き写しとされる女性です。光源氏が思慕し続けた相手で、源氏との間に不義の子（後の冷泉帝）をもうけます。」","answer":"藤壺","accept":["藤壺"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["徒然草の内容の多様性","藤壺","源氏物語の構成"]},{"id":"q146","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は藤壺の姪で、幼い頃に源氏に見出され引き取られ理想の女性として育てられました。源氏の正妻格として長く連れ添いますが、女三の宮の降嫁により苦悩し、先立って亡くなります。」","answer":"紫の上","accept":["紫の上"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["紫の上","更級日記の内容","枕草子の三つの章段"]},{"id":"q147","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「「若紫」の巻は、源氏が幼い紫の上（若紫）と出会う場面を描きます。北山で病気療養中の源氏が、藤壺に面影の似た少女を垣間見て心引かれます。」","answer":"若紫の巻","accept":["若紫の巻"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["徒然草の作者と成立","若紫の巻","「神無月のころ」の段"]},{"id":"q148","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「六条御息所は教養高い貴婦人ですが、源氏への嫉妬から生霊・死霊となり、夕顔・葵の上・紫の上を苦しめます。「葵」の巻での葵の上の死は物の怪の代表的場面です。」","answer":"六条御息所と物の怪","accept":["六条御息所と物の怪"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["光源氏","宇治十帖","六条御息所と物の怪"]},{"id":"q149","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「源氏をめぐる女性には、夕顔・空蝉・末摘花・明石の君・花散里・朧月夜・女三の宮らがいます。それぞれ身分や性格が描き分けられ、明石の君が産んだ娘は後に中宮となります。」","answer":"主要な女性たちの関係","accept":["主要な女性たちの関係"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["「神無月のころ」の段","主要な女性たちの関係","もののあはれ"]},{"id":"q150","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は第三部にあたり、源氏の死後を描きます。源氏の子とされる薫（実は柏木の子）と孫の匂宮が、宇治の姫君・大君・中の君・浮舟をめぐって織りなす恋の物語です。」","answer":"宇治十帖","accept":["宇治十帖"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["若紫の巻","宇治十帖","源氏物語の構成"]},{"id":"q151","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『源氏物語』の主題は【　　　】とされ、江戸時代の本居宣長が『源氏物語玉の小櫛』で論じました。物事に触れて自然にわき起こるしみじみとした情趣を指し、源氏物語の美的理念として頻出する重要概念です。」","answer":"もののあはれ","accept":["もののあはれ"],"hot":true,"source":"13_頻出作品_源氏物語.md","choices":["平家物語「敦盛の最期」","伊勢物語「筒井筒」","もののあはれ"]},{"id":"q152","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『枕草子』は清少納言が平安中期に著した日本最初の随筆です。作者は一条天皇の中宮定子に女房として仕えました。」","answer":"枕草子の作者と成立","accept":["枕草子の作者と成立"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["枕草子の作者と成立","竹取物語の内容","おくのほそ道"]},{"id":"q153","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『枕草子』は内容から三種に分類されます。「ものはづくし（類聚的章段）」（例：山は・虫は）、宮廷生活を回想する「日記的章段」、自然や人生への感想を述べる「随想的章段」です。」","answer":"枕草子の三つの章段","accept":["枕草子の三つの章段"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["大鏡の内容と形式","徒然草の作者と成立","枕草子の三つの章段"]},{"id":"q154","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「冒頭【　　　】は、四季それぞれの最も趣深い時と情景を述べた随想的章段です。春は明け方、夏は夜、秋は夕暮れ、冬は早朝（つとめて）を挙げます。」","answer":"「春はあけぼの」の段","accept":["「春はあけぼの」の段","春はあけぼのの段","春はあけぼの"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["「春はあけぼの」の段","平家物語「敦盛の最期」","徒然草の作者と成立"]},{"id":"q155","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『枕草子』を貫く美意識は【　　　】で、明るく知的で客観的な美を表します。対象を鋭く観察し、理知的に「趣がある・興味深い」と捉える態度が特徴です。」","answer":"枕草子の美意識「をかし」","accept":["枕草子の美意識「をかし」","枕草子の美意識をかし","をかし"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["今昔物語集","枕草子の美意識「をかし」","方丈記の無常観"]},{"id":"q156","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『徒然草』は兼好法師（吉田兼好・卜部兼好）が鎌倉末期に著した随筆です。作者は和歌四天王の一人で、出家して隠遁生活を送りました。」","answer":"徒然草の作者と成立","accept":["徒然草の作者と成立"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["更級日記の内容","枕草子の三つの章段","徒然草の作者と成立"]},{"id":"q157","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『徒然草』は約240段から成り、内容は無常観・処世訓・有職故実・自然観・芸道論・説話など多岐にわたります。一貫したテーマはなく、折に触れての感想を自由に記した点が特徴です。」","answer":"徒然草の内容の多様性","accept":["徒然草の内容の多様性"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["平家物語「敦盛の最期」","徒然草の内容の多様性","もののあはれ"]},{"id":"q158","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は、閑居の僧の庵を訪ねた話です。趣のある庵に感心していると、大きな柑子の木が厳重に囲ってあるのを見て興ざめする、という教訓的逸話です。」","answer":"「神無月のころ」の段","accept":["「神無月のころ」の段","神無月のころの段","神無月のころ"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["「神無月のころ」の段","紫の上","伊勢物語「筒井筒」"]},{"id":"q159","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は、石清水八幡宮を参詣した法師が、麓の付属の社だけを拝んで本宮（山上）を拝まずに帰った失敗譚です。「少しのことにも先達はあらまほしきことなり」と結ばれ、教訓を説く頻出段です。」","answer":"「仁和寺にある法師」の段","accept":["「仁和寺にある法師」の段","仁和寺にある法師の段","仁和寺にある法師"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["伊勢物語「東下り」","若紫の巻","「仁和寺にある法師」の段"]},{"id":"q160","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『徒然草』は中世的無常観を基調としつつ、「花は盛りに、月は隈なきをのみ見るものかは」のように、完全でないもの・移ろいゆくものに美を見出す価値観を示します。不完全の美・余情を尊ぶ中世的美意識が頻出です。」","answer":"徒然草の無常観と美意識","accept":["徒然草の無常観と美意識"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["今昔物語集","徒然草の無常観と美意識","土佐日記の内容"]},{"id":"q161","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「両作は三大随筆ですが、成立時代と美意識が異なります。『枕草子』は平安・宮廷的・「をかし」の明るい美、『徒然草』は鎌倉末・隠者的・無常観に基づく美です。」","answer":"枕草子と徒然草の比較","accept":["枕草子と徒然草の比較"],"hot":true,"source":"14_頻出作品_枕草子と徒然草.md","choices":["更級日記の内容","枕草子と徒然草の比較","「春はあけぼの」の段"]},{"id":"q162","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『竹取物語』は、竹から生まれたかぐや姫が五人の貴公子と帝の求婚を退け、月へ昇天する物語です。五人の求婚者にはそれぞれ難題が課され失敗します。」","answer":"竹取物語の内容","accept":["竹取物語の内容"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["若紫の巻","竹取物語の内容","徒然草の無常観と美意識"]},{"id":"q163","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『伊勢物語』の【　　　】は、都を離れた「昔男（業平）」が東国へ下る道中を描きます。三河の八橋で「かきつばた」を折句に詠み、隅田川では都鳥に都への思いを託します。」","answer":"伊勢物語「東下り」","accept":["伊勢物語「東下り」","伊勢物語東下り","東下り"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["おくのほそ道","光源氏","伊勢物語「東下り」"]},{"id":"q164","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『伊勢物語』の【　　　】は、幼なじみの男女が成長して結ばれる話です。井戸の周りで背くらべをした二人が和歌を贈り合って夫婦になります。」","answer":"伊勢物語「筒井筒」","accept":["伊勢物語「筒井筒」","伊勢物語筒井筒","筒井筒"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["伊勢物語「筒井筒」","おくのほそ道","今昔物語集"]},{"id":"q165","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『土佐日記』は紀貫之が土佐国司の任を終え京へ帰る55日間の船旅を、女性に仮託して仮名で記した日記です。任地で亡くした娘への哀惜が全編を貫きます。」","answer":"土佐日記の内容","accept":["土佐日記の内容"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["主要な女性たちの関係","土佐日記の内容","光源氏"]},{"id":"q166","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『更級日記』は菅原孝標女による回想録で、物語（特に源氏物語）にあこがれた少女時代から晩年までを綴ります。東国から上京し物語に夢中になった日々を回想し、信仰に傾く晩年に至ります。」","answer":"更級日記の内容","accept":["更級日記の内容"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["枕草子の作者と成立","更級日記の内容","枕草子の美意識「をかし」"]},{"id":"q167","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『大鏡』は藤原道長の栄華を中心に、大宅世継と夏山繁樹という二人の老人の対話形式で歴史を語る歴史物語です。批判精神を含む「鏡物」の代表で、紀伝体をとります。」","answer":"大鏡の内容と形式","accept":["大鏡の内容と形式"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["伊勢物語「東下り」","大鏡の内容と形式","若紫の巻"]},{"id":"q168","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『方丈記』は鴨長明が無常観を主題に著した随筆です。「ゆく河の流れは絶えずして、しかももとの水にあらず」の冒頭で世の無常を説き、五大災厄を記録した後、方丈の庵での閑居を描きます。」","answer":"方丈記の無常観","accept":["方丈記の無常観"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["徒然草の無常観と美意識","方丈記の無常観","桐壺の巻と桐壺更衣"]},{"id":"q169","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『平家物語』は平家一門の栄華と滅亡を仏教的無常観で描く軍記物語です。「祇園精舎の鐘の声、諸行無常の響きあり。」","answer":"平家物語の無常観","accept":["平家物語の無常観"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["平家物語の無常観","主要な女性たちの関係","若紫の巻"]},{"id":"q170","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「『平家物語』の【　　　】は、熊谷直実が我が子ほどの年若い平敦盛を討つ場面です。直実は敦盛を助けたいと思いながらも討たざるを得ず、武士の無常を痛感して出家を志します。」","answer":"平家物語「敦盛の最期」","accept":["平家物語「敦盛の最期」","平家物語敦盛の最期","敦盛の最期"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["平家物語「敦盛の最期」","紫の上","伊勢物語「東下り」"]},{"id":"q171","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は松尾芭蕉の俳諧紀行文で、「月日は百代の過客にして、行きかふ年もまた旅人なり」で始まります。各地で名句を詠み、「夏草や兵どもが夢の跡」「閑さや岩にしみ入る蝉の声」などが有名です。」","answer":"おくのほそ道","accept":["おくのほそ道"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["おくのほそ道","若紫の巻","枕草子の美意識「をかし」"]},{"id":"q172","theme":"作品理解","question":"次の説明が指すものを答えなさい。\n「【　　　】は平安後期成立の日本最大の説話集で、作者未詳です。天竺（インド）・震旦（中国）・本朝（日本）の三部に分かれ、各話が「今は昔」で始まります。」","answer":"今昔物語集","accept":["今昔物語集"],"hot":true,"source":"15_頻出作品_その他の頻出作品.md","choices":["若紫の巻","今昔物語集","徒然草の無常観と美意識"]},{"id":"q173","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「平安時代は太陰太陽暦（旧暦）を用い、現在の暦より約1〜2か月早く季節が進みます。一月〜三月が春、四月〜六月が夏、七月〜九月が秋、十月〜十二月が冬です。」","answer":"旧暦と季節のずれ","accept":["旧暦と季節のずれ"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["本歌取り","旧暦と季節のずれ","「あき」の掛詞と恋の歌"]},{"id":"q174","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「和歌では月を異名で詠みます。睦月（一月）・如月（二月）・弥生（三月）・卯月（四月）・皐月（五月）・水無月（六月）・文月（七月）・葉月（八月）・長月（九月）・神無月（十月）・霜月（十一月）・師走（十二月）です。」","answer":"月の異名","accept":["月の異名"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["月の異名","藤原定家","時代背景 ― 平安貴族の恋愛"]},{"id":"q175","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「平安貴族の結婚は、男が女の家に通う【　　　】が基本で、一夫多妻でした。男が三夜続けて通うと結婚が成立します。」","answer":"通い婚","accept":["通い婚"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["通い婚","屏風歌・歌合の文化","新古今和歌集の歌風"]},{"id":"q176","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「男女が一夜を共にした翌朝、男が帰宅後すぐに女へ送る手紙を【　　　】といいます。早く届くほど愛情が深いとされ、和歌が添えられました。」","answer":"後朝の文","accept":["後朝の文"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["花さそふ嵐の庭の","式子内親王","後朝の文"]},{"id":"q177","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「男が物のすき間から女性の姿をのぞき見ることを【　　　】といい、恋の始まりのきっかけになりました。当時、貴族の女性は親兄弟以外に姿を見せないのが普通で、【　　　】によって恋心が芽生えます。」","answer":"垣間見","accept":["垣間見"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["垣間見","花の色は移りにけりな","通い婚"]},{"id":"q178","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「「物忌み」は不吉な日に身を慎んで家に籠もること、「方違え」は目的地が縁起の悪い方角のとき別の家を経由する習慣です。これらが原因で男女が会えなかったり思わぬ出会いが生じたりします。」","answer":"物忌みと方違え","accept":["物忌みと方違え"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["時代背景 ― 出家と隠遁","物忌みと方違え","時代背景 ― 平安貴族の恋愛"]},{"id":"q179","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「当時、夢に人が現れるのは相手が自分を強く思っているからだ、という俗信がありました。「思ひつつ寝ればや人の見えつらむ」（小野小町）のように、夢を恋の証と捉えます。」","answer":"夢と魂・恋の俗信","accept":["夢と魂・恋の俗信"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["新古今和歌集の歌風","通い婚","夢と魂・恋の俗信"]},{"id":"q180","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「俗世を離れて仏門に入ることを「出家・遁世」といい、和歌では「世を背く」【　　　】「世を厭ふ」と表現されます。失恋・死別・無常感が出家の動機となります。」","answer":"出家と「世を捨つ」","accept":["出家と「世を捨つ」","出家と世を捨つ","世を捨つ"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["出家と「世を捨つ」","式子内親王の忍ぶ恋","垣間見"]},{"id":"q181","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「賀茂祭（葵祭）は平安京最大の祭礼で、単に「祭」といえばこれを指しました。賀茂神社に奉仕する未婚の皇女を斎院、伊勢神宮に仕える皇女を【　　　】といいます。」","answer":"賀茂祭と斎院・斎宮","accept":["賀茂祭と斎院・斎宮"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["在原業平","古今和歌集の歌風","賀茂祭と斎院・斎宮"]},{"id":"q182","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「五節句は和歌の格好の題材です。【　　　】（七月七日）は牽牛・織女の年一度の逢瀬で恋歌に、重陽（九月九日）は菊で長寿を祝う宴に詠まれます。」","answer":"七夕・重陽などの節句","accept":["七夕・重陽などの節句"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["七夕・重陽などの節句","ちはやぶる神代も聞かず竜田川","後鳥羽院"]},{"id":"q183","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「近親者が亡くなると一定期間喪に服し、喪服には鈍色（にびいろ＝濃い灰色）を着ました。和歌で「鈍色の衣」「藤衣（喪服）」が出れば死別・哀傷の場面と判断できます。」","answer":"服喪と喪服の色","accept":["服喪と喪服の色"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["服喪と喪服の色","立ち別れいなばの山の","三大歌集の比較"]},{"id":"q184","theme":"和歌","question":"次の説明が指すものを答えなさい。\n「貴族にとって【　　　】・昇進は重大関心事で、人事を決める儀式を「除目（じもく）」といいます。望む官職に就けない不遇を【　　　】「数ならぬ身」と嘆く歌が多く詠まれました。」","answer":"官位・除目と「身の沈み」","accept":["官位・除目と「身の沈み」","官位・除目と身の沈み","身の沈み"],"hot":true,"source":"16_和歌_読解に必要な時代背景と古文常識.md","choices":["官位・除目と「身の沈み」","花さそふ嵐の庭の","物忌みと方違え"]}];
